t Company Name","token":"{{party_b_company}}","category":"party_b","required":true,"description":"Consultant legal entity name (e.g., Ltd/LLP/PLC)"},{"id":"party_b_title","type":"text","label":"Consultant Signatory Title","token":"{{party_b_title}}","category":"party_b","required":false,"description":"Job title of authorised signatory"},{"id":"party_b_registered_number","type":"text","label":"Consultant Company Registered Number","token":"{{party_b_registered_number}}","category":"party_b","required":false,"description":"Companies House registered number (if applicable)"},{"id":"effective_date","type":"date","label":"Effective Date","token":"{{effective_date}}","category":"dates","required":true,"description":"Agreement start date"},{"id":"expiration_date","type":"date","label":"Expiration Date","token":"{{expiration_date}}","category":"dates","required":false,"description":"Agreement end date (if fixed-term)"},{"id":"signature_date","type":"date","label":"Signature Date","token":"{{signature_date}}","category":"dates","required":false,"description":"Date of signing"},{"id":"notice_period","type":"number","label":"Notice Period (days)","token":"{{notice_period}}","category":"terms","required":false,"description":"Days'' notice for termination for convenience"},{"id":"services_description","type":"textarea","label":"Services Description / Statement of Work","token":"{{services_description}}","category":"project","required":true,"description":"Detailed description of services, assumptions, scope and exclusions"},{"id":"deliverables_schedule","type":"textarea","label":"Deliverables Schedule and Acceptance Criteria","token":"{{deliverables_schedule}}","category":"project","required":false,"description":"List of deliverables, formats, due dates, acceptance criteria and delivery methods"},{"id":"milestones","type":"textarea","label":"Milestones","token":"{{milestones}}","category":"project","required":false,"description":"Project milestones, stage gates, and milestone fees (if any)"},{"id":"acceptance_period_days","type":"number","label":"Acceptance Period (Business Days)","token":"{{acceptance_period_days}}","category":"project","required":false,"description":"Client review period for deliverables"},{"id":"correction_period_days","type":"number","label":"Correction Period (Business Days)","token":"{{correction_period_days}}","category":"project","required":false,"description":"Consultant remedy period for rejected deliverables"},{"id":"change_request_form","type":"textarea","label":"Change Request Form/Process","token":"{{change_request_form}}","category":"project","required":false,"description":"Template or process used for change requests"},{"id":"payment_amount","type":"currency","label":"Fixed Fee Amount","token":"{{payment_amount}}","category":"financial","required":false,"description":"Fixed fee, if applicable"},{"id":"hourly_rate","type":"currency","label":"Rate Amount","token":"{{hourly_rate}}","category":"financial","required":false,"description":"Rate amount (per hour/day as specified)"},{"id":"rate_unit","type":"text","label":"Rate Unit","token":"{{rate_unit}}","category":"financial","required":false,"description":"Unit for the rate (e.g., hour, day)"},{"id":"currency","type":"text","label":"Currency","token":"{{currency}}","category":"financial","required":false,"description":"Currency code (e.g., GBP)"},{"id":"payment_terms_days","type":"number","label":"Payment Terms (days)","token":"{{payment_terms_days}}","category":"financial","required":false,"description":"Number of days to pay undisputed invoices"},{"id":"client_invoice_email","type":"email","label":"Client Invoice Email","token":"{{client_invoice_email}}","category":"financial","required":false,"description":"Email address for invoice submission"},{"id":"purchase_order_number","type":"text","label":"Purchase Order Number","token":"{{purchase_order_number}}","category":"financial","required":false,"description":"PO number required for invoicing (if applicable)"},{"id":"bank_details","type":"textarea","label":"Consultant Bank Details","token":"{{bank_details}}","category":"financial","required":false,"description":"Bank name, account name, sort code, account number, IBAN/SWIFT (if relevant)"},{"id":"maximum_expenses","type":"currency","label":"Expense Cap","token":"{{maximum_expenses}}","category":"financial","required":false,"description":"Maximum reimbursable expenses amount (if any)"},{"id":"expenses_policy_url","type":"text","label":"Expenses Policy URL/Reference","token":"{{expenses_policy_url}}","category":"financial","required":false,"description":"Link/reference to agreed expenses policy"},{"id":"pre_approved_expenses_description","type":"textarea","label":"Pre-Approved Expenses Description","token":"{{pre_approved_expenses_description}}","category":"financial","required":false,"description":"Categories of expenses approved for reimbursement"},{"id":"services_location","type":"text","label":"Services Location","token":"{{services_location}}","category":"project","required":false,"description":"Primary location(s) where services will be performed"},{"id":"working_hours","type":"text","label":"Indicative Working Hours","token":"{{working_hours}}","category":"project","required":false,"description":"Any indicative working hours for planning (non-employment)"},{"id":"key_personnel","type":"textarea","label":"Key Personnel","token":"{{key_personnel}}","category":"project","required":false,"description":"Named individuals/roles treated as key personnel"},{"id":"client_policies_url","type":"text","label":"Client Policies Reference","token":"{{client_policies_url}}","category":"compliance","required":false,"description":"Link or reference to client policies applicable to contractors (security, acceptable use, etc.)"},{"id":"termination_assistance_days","type":"number","label":"Termination Assistance Days","token":"{{termination_assistance_days}}","category":"terms","required":false,"description":"Number of days for optional transition assistance after termination"},{"id":"confidentiality_term_years","type":"number","label":"Confidentiality Term (years)","token":"{{confidentiality_term_years}}","category":"terms","required":false,"description":"Years confidentiality obligations continue after termination (excluding trade secrets)"},{"id":"data_processing_details","type":"textarea","label":"Data Processing Details (UK GDPR Art 28)","token":"{{data_processing_details}}","category":"privacy","required":false,"description":"Subject matter, duration, nature/purpose, types of personal data, categories of data subjects"},{"id":"security_measures","type":"textarea","label":"Security Measures","token":"{{security_measures}}","category":"privacy","required":false,"description":"Technical and organisational measures (TOMs) implemented by Consultant"},{"id":"permitted_subprocessors","type":"textarea","label":"Permitted Sub-processors","token":"{{permitted_subprocessors}}","category":"privacy","required":false,"description":"List of approved sub-processors or a link/reference"},{"id":"international_transfer_mechanism","type":"text","label":"International Transfer Mechanism","token":"{{international_transfer_mechanism}}","category":"privacy","required":false,"description":"Mechanism for international transfers (e.g., UK IDTA, UK Addendum)"},{"id":"pi_insurance_amount","type":"currency","label":"Professional Indemnity Insurance Amount","token":"{{pi_insurance_amount}}","category":"insurance","required":false,"description":"Minimum PI insurance coverage"},{"id":"pl_insurance_amount","type":"currency","label":"Public Liability Insurance Amount","token":"{{pl_insurance_amount}}","category":"insurance","required":false,"description":"Minimum public liability coverage"},{"id":"employers_liability_amount","type":"currency","label":"Employer’s Liability Insurance Amount","token":"{{employers_liability_amount}}","category":"insurance","required":false,"description":"Minimum employer’s liability coverage (if applicable)"},{"id":"liability_cap","type":"text","label":"Liability Cap","token":"{{liability_cap}}","category":"legal","required":false,"description":"Express liability cap (e.g., ''£100,000'' or ''125% of Charges paid in prior 12 months'')"},{"id":"non_solicitation_term_months","type":"number","label":"Non-Solicitation Term (months)","token":"{{non_solicitation_term_months}}","category":"optional","required":false,"description":"Duration for optional restrictive covenants"},{"id":"restrictive_covenant_territory","type":"text","label":"Restrictive Covenant Territory","token":"{{restrictive_covenant_territory}}","category":"optional","required":false,"description":"Territory for optional non-compete (if used)"},{"id":"dispute_mediation_body","type":"text","label":"Mediation Body","token":"{{dispute_mediation_body}}","category":"legal","required":false,"description":"Mediation provider/procedure (e.g., CEDR)"},{"id":"contract_manager_client","type":"text","label":"Client Contract Manager","token":"{{contract_manager_client}}","category":"project","required":false,"description":"Name/role/email of Client''s contract manager"},{"id":"contract_manager_consultant","type":"text","label":"Consultant Contract Manager","token":"{{contract_manager_consultant}}","category":"project","required":false,"description":"Name/role/email of Consultant''s contract manager"}]'::jsonb,
