Period (Business Days)","token":"{{acceptance_period_days}}","category":"terms","required":false,"description":"Number of business days for client review/acceptance"},{"id":"notice_period","type":"number","label":"Termination Notice Period (days)","token":"{{notice_period}}","category":"terms","required":false,"description":"Days notice for termination for convenience"},{"id":"cure_period_days","type":"number","label":"Cure Period (days)","token":"{{cure_period_days}}","category":"terms","required":false,"description":"Days to remedy a material breach after notice"},{"id":"confidentiality_period","type":"number","label":"Confidentiality Period (years)","token":"{{confidentiality_period}}","category":"terms","required":false,"description":"Years confidentiality survives after termination (trade secrets may last longer)"},{"id":"payment_currency","type":"text","label":"Currency","token":"{{payment_currency}}","category":"financial","required":false,"description":"Currency for fees (e.g., GBP)"},{"id":"hourly_rate","type":"currency","label":"Daily Rate","token":"{{hourly_rate}}","category":"financial","required":false,"description":"Rate per day (used for time and materials and change orders)"},{"id":"payment_amount","type":"currency","label":"Fixed Project Fee","token":"{{payment_amount}}","category":"financial","required":false,"description":"Total fixed fee (if applicable)"},{"id":"retainer_amount","type":"currency","label":"Monthly Retainer Amount","token":"{{retainer_amount}}","category":"financial","required":false,"description":"Retainer fee per month (if applicable)"},{"id":"deposit_amount","type":"currency","label":"Deposit Amount","token":"{{deposit_amount}}","category":"financial","required":false,"description":"Upfront deposit amount (if applicable)"},{"id":"invoice_frequency","type":"text","label":"Invoice Frequency","token":"{{invoice_frequency}}","category":"financial","required":false,"description":"e.g., monthly in arrears / per milestone / on completion"},{"id":"invoice_due_days","type":"number","label":"Invoice Due Days","token":"{{invoice_due_days}}","category":"financial","required":false,"description":"Payment terms in days from receipt of invoice"},{"id":"freelancer_bank_details","type":"textarea","label":"Freelancer Bank Details","token":"{{freelancer_bank_details}}","category":"financial","required":false,"description":"Bank account details for payment"},{"id":"expense_cap_amount","type":"currency","label":"Expense Cap Amount","token":"{{expense_cap_amount}}","category":"financial","required":false,"description":"Maximum reimbursable expenses (if any)"},{"id":"revision_rounds_included","type":"number","label":"Included Revision Rounds","token":"{{revision_rounds_included}}","category":"project","required":false,"description":"Number of revision rounds included in the fee (if applicable)"},{"id":"revision_response_days","type":"number","label":"Client Feedback Window (Business Days)","token":"{{revision_response_days}}","category":"project","required":false,"description":"Business days for client to provide feedback"},{"id":"ir35_status","type":"text","label":"IR35 Intended Status","token":"{{ir35_status}}","category":"compliance","required":false,"description":"e.g., Outside IR35 / Inside IR35 / To be determined by SDS"},{"id":"personal_data_description","type":"textarea","label":"Personal Data Processing Details","token":"{{personal_data_description}}","category":"privacy","required":false,"description":"Types of personal data, categories of data subjects, purpose, and duration of processing"},{"id":"security_measures","type":"textarea","label":"Security Measures","token":"{{security_measures}}","category":"privacy","required":false,"description":"Technical and organisational security measures (or reference to an info-sec policy)"},{"id":"breach_notification_hours","type":"number","label":"Breach Notification Hours","token":"{{breach_notification_hours}}","category":"privacy","required":false,"description":"Hours within which freelancer must notify client after becoming aware of a personal data breach"},{"id":"client_project_contact_name","type":"text","label":"Client Project Contact Name","token":"{{client_project_contact_name}}","category":"project","required":false,"description":"Primary client point of contact"},{"id":"client_project_contact_email","type":"email","label":"Client Project Contact Email","token":"{{client_project_contact_email}}","category":"project","required":false,"description":"Email for day-to-day project communications"},{"id":"liability_cap_amount","type":"currency","label":"Alternative Liability Cap (optional)","token":"{{liability_cap_amount}}","category":"legal","required":false,"description":"If specified, overrides the default fee-based cap in Section 16.3"},{"id":"cancellation_fee_terms","type":"textarea","label":"Cancellation Fee Terms (optional)","token":"{{cancellation_fee_terms}}","category":"terms","required":false,"description":"Any agreed cancellation fee/booking terms for termination for convenience"},{"id":"pi_insurance_amount","type":"currency","label":"Professional Indemnity Insurance Amount (optional)","token":"{{pi_insurance_amount}}","category":"insurance","required":false,"description":"Minimum PI insurance cover"},{"id":"public_liability_insurance_amount","type":"currency","label":"Public Liability Insurance Amount (optional)","token":"{{public_liability_insurance_amount}}","category":"insurance","required":false,"description":"Minimum public liability insurance cover"},{"id":"non_solicitation_period_months","type":"number","label":"Non-Solicitation Period (months)","token":"{{non_solicitation_period_months}}","category":"terms","required":false,"description":"Months after termination for non-solicitation restriction"},{"id":"non_solicitation_fee_amount","type":"currency","label":"Non-Solicitation Recruitment Fee (optional)","token":"{{non_solicitation_fee_amount}}","category":"terms","required":false,"description":"Optional fixed fee payable upon breach, if agreed"}]'::jsonb,
