  placeholders = '[{"id":"party_a_email","type":"email","label":"Client Email","token":"{{party_a_email}}","category":"party_a","required":true,"autofillKey":"email","description":"Email address for notices and operational communications"},{"id":"party_a_name","type":"text","label":"Client Signatory Name","token":"{{party_a_name}}","category":"party_a","required":true,"autofillKey":"name","description":"Full legal name of authorised signatory"},{"id":"party_a_address","type":"textarea","label":"Client Registered Address","token":"{{party_a_address}}","category":"party_a","required":true,"autofillKey":"address","description":"Registered office address"},{"id":"party_a_company","type":"text","label":"Client Company Name","token":"{{party_a_company}}","category":"party_a","required":true,"autofillKey":"company_name","description":"Legal name of Client entity (e.g., Ltd, PLC, LLP)"},{"id":"party_a_company_number","type":"text","label":"Client Company Number","token":"{{party_a_company_number}}","category":"party_a","required":false,"description":"Companies House registration number (if applicable)"},{"id":"party_a_title","type":"text","label":"Client Signatory Title","token":"{{party_a_title}}","category":"party_a","required":false,"autofillKey":"job_title","description":"Job title of authorised signatory"},{"id":"party_b_email","type":"email","label":"Consultant Email","token":"{{party_b_email}}","category":"party_b","required":true,"description":"Email address for notices and operational communications"},{"id":"party_b_name","type":"text","label":"Consultant Signatory Name","token":"{{party_b_name}}","category":"party_b","required":true,"description":"Full legal name of authorised signatory"},{"id":"party_b_address","type":"textarea","label":"Consultant Address","token":"{{party_b_address}}","category":"party_b","required":true,"description":"Business address"},{"id":"party_b_company","type":"text","label":"Consultant Company/Trading Name","token":"{{party_b_company}}","category":"party_b","required":true,"description":"Legal entity name or trading name"},{"id":"party_b_company_number","type":"text","label":"Consultant Company Number","token":"{{party_b_company_number}}","category":"party_b","required":false,"description":"Registration number (if applicable)"},{"id":"party_b_jurisdiction","type":"text","label":"Consultant Incorporation Jurisdiction","token":"{{party_b_jurisdiction}}","category":"party_b","required":false,"description":"Jurisdiction of incorporation if not England and Wales"},{"id":"party_b_title","type":"text","label":"Consultant Signatory Title","token":"{{party_b_title}}","category":"party_b","required":false,"description":"Job title of authorised signatory"},{"id":"effective_date","type":"date","label":"Effective Date","token":"{{effective_date}}","category":"dates","required":true,"description":"Agreement start date"},{"id":"expiration_date","type":"date","label":"Expiration Date","token":"{{expiration_date}}","category":"dates","required":false,"description":"Agreement end date (if fixed term)"},{"id":"signature_date","type":"date","label":"Signature Date","token":"{{signature_date}}","category":"dates","required":false,"description":"Date of execution"},{"id":"notice_period","type":"number","label":"Termination Notice Period (days)","token":"{{notice_period}}","category":"terms","required":false,"description":"Days'' notice for termination for convenience"},{"id":"transition_assistance_days","type":"number","label":"Transition Assistance Days","token":"{{transition_assistance_days}}","category":"terms","required":false,"description":"Maximum Business Days of post-termination transition support"},{"id":"hourly_rate","type":"currency","label":"Daily/Hourly Rate","token":"{{hourly_rate}}","category":"financial","required":false,"description":"Time-based rate (as applicable)"},{"id":"payment_amount","type":"currency","label":"Fixed Fee / Total Fee","token":"{{payment_amount}}","category":"financial","required":false,"description":"Fixed fee amount (if applicable)"},{"id":"invoicing_frequency","type":"text","label":"Invoicing Frequency","token":"{{invoicing_frequency}}","category":"financial","required":false,"description":"E.g., monthly in arrears, per milestone, weekly"},{"id":"payment_terms_days","type":"number","label":"Payment Terms (days)","token":"{{payment_terms_days}}","category":"financial","required":false,"description":"Number of days for payment of undisputed invoices"},{"id":"invoice_submission_email","type":"email","label":"Invoice Submission Email","token":"{{invoice_submission_email}}","category":"financial","required":false,"description":"Email address for invoice submission"},{"id":"services_description","type":"textarea","label":"Services / Statement of Work","token":"{{services_description}}","category":"project","required":true,"description":"Description of services, deliverables, milestones, acceptance criteria, and fees"},{"id":"acceptance_period_days","type":"number","label":"Acceptance Review Period (Business Days)","token":"{{acceptance_period_days}}","category":"project","required":false,"description":"Number of Business Days for Client to accept or reject deliverables"},{"id":"confidentiality_duration_years","type":"number","label":"Confidentiality Duration (years)","token":"{{confidentiality_duration_years}}","category":"terms","required":false,"description":"Post-termination confidentiality period (Trade Secrets remain protected as long as secret)"},{"id":"client_security_policy_url","type":"text","label":"Client Security Policy URL (optional)","token":"{{client_security_policy_url}}","category":"security","required":false,"description":"Link or reference to client security requirements (if any)"},{"id":"data_breach_notice_hours","type":"number","label":"Data Breach Notice (hours)","token":"{{data_breach_notice_hours}}","category":"data_protection","required":false,"description":"Hours within which Consultant must notify Client after becoming aware of a Personal Data Breach"},{"id":"data_subject_categories","type":"textarea","label":"Categories of Data Subjects","token":"{{data_subject_categories}}","category":"data_protection","required":false,"description":"E.g., employees, customers, users, prospects"},{"id":"personal_data_types","type":"textarea","label":"Types of Personal Data","token":"{{personal_data_types}}","category":"data_protection","required":false,"description":"E.g., name, email, identifiers, usage data"},{"id":"special_category_data_details","type":"textarea","label":"Special Category Data (if any)","token":"{{special_category_data_details}}","category":"data_protection","required":false,"description":"Describe Special Category Data processed or state ''none''"},{"id":"subprocessor_list","type":"textarea","label":"Sub-processors (if any)","token":"{{subprocessor_list}}","category":"data_protection","required":false,"description":"List of sub-processors or state ''none''"},{"id":"data_processing_locations","type":"textarea","label":"Processing Locations","token":"{{data_processing_locations}}","category":"data_protection","required":false,"description":"Countries/regions where Personal Data may be processed"},{"id":"liability_cap_amount","type":"currency","label":"Liability Cap Amount","token":"{{liability_cap_amount}}","category":"legal","required":false,"description":"Cap on aggregate liability (e.g., fees paid in last 12 months or a fixed amount)"},{"id":"claims_time_limit_months","type":"number","label":"Claims Time Limit (months)","token":"{{claims_time_limit_months}}","category":"legal","required":false,"description":"Optional contractual limitation period for bringing claims"},{"id":"insurance_required","type":"text","label":"Insurance Required (yes/no)","token":"{{insurance_required}}","category":"insurance","required":false,"description":"Whether insurance clause is to apply"},{"id":"professional_indemnity_amount","type":"currency","label":"Professional Indemnity Limit","token":"{{professional_indemnity_amount}}","category":"insurance","required":false,"description":"Minimum limit per claim"},{"id":"public_liability_amount","type":"currency","label":"Public Liability Limit","token":"{{public_liability_amount}}","category":"insurance","required":false,"description":"Minimum limit per occurrence"},{"id":"cyber_insurance_amount","type":"currency","label":"Cyber Insurance Limit","token":"{{cyber_insurance_amount}}","category":"insurance","required":false,"description":"Minimum cyber/security liability insurance limit"},{"id":"non_solicitation_months","type":"number","label":"Non-solicitation Term (months)","token":"{{non_solicitation_months}}","category":"restrictive_covenants","required":false,"description":"Duration of non-solicitation restrictions after termination"}]'::jsonb,
  metadata = '{"note":"Includes IR35/off-payroll rules provisions","word_count":8876,"clause_count":14,"generated_at":"2025-12-28T18:00:00.000Z","jurisdiction":"uk","generator_version":"gpt-5.2","placeholder_count":40,"gpt_enhanced":true,"gpt_model":"gpt-5.2","enhanced_at":"2025-12-28T23:32:46.369Z"}'::jsonb
WHERE id = '422e55ca-cb3a-445f-99fa-a0e8c43c6671';

-- Update: Mutual Non-Disclosure Agreement (England and Wales)
UPDATE contract_templates SET
  preamble = 'This Mutual Non-Disclosure Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date") by and between:

(A) {{party_a_company}}, a company incorporated and registered in England and Wales (company number {{party_a_company_number}}) whose registered office is at {{party_a_address}} ("Party A" and/or "{{party_a_name}}"); and

(B) {{party_b_company}}, a company incorporated and registered in England and Wales (company number {{party_b_company_number}}) whose registered office is at {{party_b_address}} ("Party B" and/or "{{party_b_name}}").

Party A and Party B are each a "Party" and together the "Parties".

This Agreement is intended to be legally binding. The Parties agree that this Agreement may be executed in counterparts and by electronic signature in accordance with Clause 9.12.',
  recitals = 'WHEREAS, the Parties wish to explore, discuss and/or evaluate a potential business relationship concerning {{purpose}} (the "Purpose");

WHEREAS, in connection with the Purpose, each Party may disclose or make available to the other Party certain confidential, proprietary and/or commercially sensitive information, including information that may constitute a trade secret;

WHEREAS, the Parties wish to protect such information and agree to restrictions on its use and disclosure, in accordance with the terms of this Agreement and applicable law, including the Trade Secrets (Enforcement, etc.) Regulations 2018;

NOW, THEREFORE, in consideration of the mutual promises and covenants contained herein (the sufficiency of which is acknowledged), the Parties agree as follows:',
  clauses = '[{"id":"definitions","type":"standard","order":1,"title":"1. DEFINITIONS","content":"1.1 In this Agreement, the following expressions shall have the meanings set out below (and cognate expressions shall be construed accordingly):\n\n1.2 \"Affiliate\" means, in relation to a Party, any entity that directly or indirectly Controls, is Controlled by, or is under common Control with that Party from time to time.\n\n1.3 \"Business Day\" means a day other than a Saturday, Sunday or public holiday in England when banks in London are open for business.\n\n1.4 \"Confidential Information\" means any information or data (in whatever form or medium and whether or not marked or stated to be confidential) disclosed or made available by or on behalf of a Party (the \"Disclosing Party\") to the other Party (the \"Receiving Party\"), whether before, on, or after the Effective Date, which:\n\n(a) is designated or identified as confidential or proprietary; or\n\n(b) ought reasonably to be understood to be confidential given its nature, the circumstances of disclosure, the identity of the Disclosing Party, and/or the Purpose.\n\n1.5 Without limiting Clause 1.4, Confidential Information includes: business plans; strategy; product roadmaps; budgets and forecasts; pricing; tenders; proposals; internal reports; management accounts; financial information; investor information; customer, client and supplier information (including contact details and requirements); marketing information; sales information; pipeline and leads; agreements and contract terms; technology and technical information; inventions and discoveries; designs; drawings; specifications; prototypes; research and development; source code and object code; software and databases; models; data sets; security architectures; penetration test results; access credentials; processes and methodologies; know-how and trade know-how; analyses; compilations; notes; summaries; extracts; and any information derived from or generated from any of the foregoing.\n\n1.6 \"Confidential Materials\" means all documents, records and materials (including any copies) containing, reflecting, derived from, or generated using Confidential Information, including notes, memoranda, analyses, presentations, emails, screenshots, recordings, extracts, samples and models.\n\n1.7 \"Control\" means the power to direct or cause the direction of the management and policies of an entity, whether through ownership of voting securities, by contract or otherwise, and \"Controlled\" shall be construed accordingly.\n\n1.8 \"Data Protection Legislation\" means all applicable data protection and privacy laws and regulations in force in the United Kingdom from time to time including: the UK GDPR; the Data Protection Act 2018; the Privacy and Electronic Communications (EC Directive) Regulations 2003 (as amended) (\"PECR\"); and any codes of practice and guidance issued by the Information Commissioner''s Office (\"ICO\") or other competent authority, in each case as amended, updated or replaced from time to time.\n\n1.9 \"Disclosing Party\" has the meaning given in Clause 1.4.\n\n1.10 \"Permitted Purpose\" means the Purpose described in the Recitals and further detailed as follows (if applicable): {{purpose}}.\n\n1.11 \"Permitted Recipients\" means (to the extent strictly necessary for the Permitted Purpose):\n\n(a) the Receiving Party''s Representatives;\n\n(b) the Receiving Party''s Affiliates and their respective Representatives, provided that the Receiving Party remains responsible for their compliance with this Agreement as if they were the Receiving Party; and\n\n(c) any other person approved in advance in writing by the Disclosing Party.\n\n1.12 \"Personal Data\" has the meaning given to it in the UK GDPR.\n\n1.13 \"Process\", \"Processed\" and \"Processing\" have the meanings given to them in the UK GDPR.\n\n1.14 \"Professional Advisers\" means a Party''s external legal advisers, accountants, tax advisers, auditors, corporate finance advisers, insurers and bankers.\n\n1.15 \"Receiving Party\" has the meaning given in Clause 1.4.\n\n1.16 \"Representatives\" means, in relation to a Party, its and its Affiliates'' directors, officers, employees, agency workers, secondees, consultants, contractors, Professional Advisers and other professional representatives who have a need to know the Confidential Information for the Permitted Purpose.\n\n1.17 \"Security Incident\" means (i) any unauthorised or unlawful access to, acquisition of, disclosure of, or loss of Confidential Information or Personal Data; (ii) any unauthorised use, alteration, deletion, corruption or destruction of Confidential Information or Personal Data; or (iii) any event that materially compromises the confidentiality, integrity or availability of Confidential Information (including ransomware or similar attacks).\n\n1.18 \"Trade Secret\" means information which constitutes a trade secret within the meaning of the Trade Secrets (Enforcement, etc.) Regulations 2018, and includes (without limitation) information that: (a) is secret in the sense that it is not, as a body or in the precise configuration and assembly of its components, generally known among or readily accessible to persons within the circles that normally deal with the kind of information in question; (b) has commercial value because it is secret; and (c) has been subject to reasonable steps under the circumstances, by the person lawfully in control of the information, to keep it secret.\n\n1.19 \"UK GDPR\" means Regulation (EU) 2016/679 as it forms part of the law of England and Wales by virtue of section 3 of the European Union (Withdrawal) Act 2018, as amended by the Data Protection, Privacy and Electronic Communications (Amendments etc) (EU Exit) Regulations 2019 and as further amended from time to time.\n\n1.20 \"writing\" or \"written\" includes email and other electronic methods of communication that create a durable record, except where this Agreement expressly requires execution.\n\n1.21 Headings are for convenience only and do not affect interpretation.\n\n1.22 References to \"including\" or \"in particular\" (or similar) shall not limit the generality of the words preceding them.\n\n1.23 References to any statute or statutory provision include (i) any subordinate legislation made under it, and (ii) any modification, consolidation, re-enactment or replacement for the time being in force.\n\n1.24 Where this Agreement imposes an obligation on the Receiving Party in respect of Confidential Information, that obligation applies equally to any Confidential Materials.\n\n1.25 Trade Secrets are included within Confidential Information. Where Confidential Information qualifies as a Trade Secret, additional statutory remedies may be available under the Trade Secrets (Enforcement, etc.) Regulations 2018."},{"id":"confidentiality_obligations","type":"standard","order":2,"title":"2. CONFIDENTIALITY OBLIGATIONS","content":"2.1 Permitted Purpose only. The Receiving Party shall:\n\n(a) use the Disclosing Party''s Confidential Information solely for the Permitted Purpose;\n\n(b) not use the Confidential Information for any other purpose, including to compete with the Disclosing Party, to obtain a commercial, strategic or other advantage unrelated to the Permitted Purpose, or to reverse engineer or replicate any products, services or processes of the Disclosing Party (subject to Clause 3);\n\n(c) not exploit the Confidential Information for its own benefit or for the benefit of any third party.\n\n2.2 Non-disclosure. Except as permitted under this Agreement, the Receiving Party shall keep the Disclosing Party''s Confidential Information strictly confidential and shall not disclose it to any person.\n\n2.3 Disclosure to Permitted Recipients.\n\n(a) The Receiving Party may disclose Confidential Information to Permitted Recipients only where and to the extent that such Permitted Recipient needs to know the Confidential Information for the Permitted Purpose.\n\n(b) Prior to disclosure to any Permitted Recipient (other than the Receiving Party''s Professional Advisers who are already subject to duties of confidentiality), the Receiving Party shall ensure that such Permitted Recipient is bound by written confidentiality obligations no less restrictive than those set out in this Agreement.\n\n(c) The Receiving Party shall be responsible for any act or omission of its Permitted Recipients as if it were the act or omission of the Receiving Party.\n\n2.4 Standard of care. The Receiving Party shall protect the Confidential Information using at least the same degree of care as it uses to protect its own confidential information of a similar nature, and in any event no less than a reasonable standard of care.\n\n2.5 Security measures.\n\n(a) The Receiving Party shall implement and maintain appropriate technical and organisational measures designed to protect Confidential Information against unauthorised access, disclosure, alteration, loss or destruction.\n\n(b) Without limitation, where Confidential Information is held electronically, the Receiving Party shall, as appropriate to the risk: limit access on a least-privilege basis; use strong authentication; apply encryption in transit and at rest where reasonably practicable; maintain anti-malware controls; and keep systems patched.\n\n(c) The Receiving Party shall not circumvent or attempt to circumvent any security measure or access control relating to the Disclosing Party''s Confidential Information.\n\n2.6 Copying and extraction.\n\n(a) The Receiving Party shall not copy, download, scrape, photograph, screen-capture, record or otherwise reproduce Confidential Information except to the extent reasonably necessary for the Permitted Purpose.\n\n(b) The Receiving Party shall ensure that any copies made are subject to this Agreement and contain (where reasonably practicable) the same confidentiality markings as the original.\n\n2.7 Minimum disclosure. The Receiving Party shall take reasonable steps to:\n\n(a) limit the amount of Confidential Information accessed or disclosed to Permitted Recipients to what is strictly necessary for the Permitted Purpose; and\n\n(b) avoid disclosing Trade Secrets unless reasonably required for the Permitted Purpose.\n\n2.8 Confidentiality of discussions and existence.\n\n(a) Subject to Clause 2.10 (compelled disclosure), each Party shall treat as Confidential Information: (i) the fact that the Parties are in discussions or negotiations regarding the Permitted Purpose; (ii) the terms of this Agreement; and (iii) the existence and status of the relationship between the Parties.\n\n(b) Clause 2.8(a) shall not prevent disclosure to Permitted Recipients or to the extent required by applicable law.\n\n2.9 No reverse engineering / decompilation.\n\n(a) To the maximum extent permitted by law, the Receiving Party shall not (and shall not permit others to) reverse engineer, decompile, disassemble or otherwise attempt to derive the composition, source code, underlying ideas, know-how or algorithms of any samples, prototypes, software, models or other tangible embodiments of Confidential Information supplied by the Disclosing Party.\n\n(b) Nothing in this Clause 2.9 is intended to restrict any right that cannot lawfully be excluded, including rights under the Copyright, Designs and Patents Act 1988 or the retained EU law provisions applicable to decompilation for interoperability, but only to the extent such rights apply and are exercised lawfully.\n\n2.10 Compelled disclosure.\n\n(a) If the Receiving Party is required by applicable law, regulation, rule of a competent authority, stock exchange requirement, or by court order, warrant, or other legal process to disclose any Confidential Information (a \"Required Disclosure\"), it may disclose only that portion of the Confidential Information that is legally required to be disclosed.\n\n(b) To the extent legally permitted, the Receiving Party shall: (i) give the Disclosing Party prompt written notice of the Required Disclosure (including the information to be disclosed and the circumstances); (ii) consult with the Disclosing Party regarding the content of the proposed disclosure; and (iii) provide reasonable assistance (at the Disclosing Party''s cost) in seeking a protective order, confidentiality ring, or other appropriate remedy.\n\n(c) If prior notice is prohibited or not reasonably practicable, the Receiving Party shall (to the extent legally permitted) notify the Disclosing Party as soon as possible after making the disclosure.\n\n2.11 Security Incidents and misuse.\n\n(a) The Receiving Party shall notify the Disclosing Party without undue delay upon becoming aware of any Security Incident involving the Disclosing Party''s Confidential Information.\n\n(b) The Receiving Party shall take reasonable steps to mitigate the effects of the Security Incident, prevent recurrence, and co-operate with the Disclosing Party''s reasonable requests for information relating to the Security Incident.\n\n2.12 Privileged information. Where Confidential Information includes material subject to legal professional privilege, the Receiving Party shall not do anything that would waive, or risk waiver of, that privilege and shall comply with the Disclosing Party''s reasonable instructions regarding handling, review and dissemination.\n\n2.13 Reservation of rights. All Confidential Information remains the property of the Disclosing Party (or its licensors). No rights are granted to the Receiving Party except the limited right to use Confidential Information for the Permitted Purpose in accordance with this Agreement.\n\n2.14 Trade secret protections. The Parties acknowledge that Trade Secrets may require specific protective measures. The Receiving Party shall treat any Trade Secret with a high degree of care and shall not disclose it except to Permitted Recipients who have a demonstrable need to know for the Permitted Purpose."},{"id":"exclusions","type":"standard","order":3,"title":"3. EXCLUSIONS FROM CONFIDENTIAL INFORMATION","content":"3.1 Exclusions. Confidential Information does not include information that the Receiving Party can demonstrate by contemporaneous written records and competent evidence:\n\n(a) is or becomes generally available to the public other than as a result of a breach of this Agreement by the Receiving Party or any of its Permitted Recipients;\n\n(b) was lawfully in the Receiving Party''s possession, free of any obligation of confidence, prior to disclosure by or on behalf of the Disclosing Party;\n\n(c) is lawfully received by the Receiving Party from a third party who is not, to the Receiving Party''s knowledge, under an obligation of confidentiality to the Disclosing Party in relation to that information;\n\n(d) is independently developed by the Receiving Party without reference to, use of, or reliance on the Disclosing Party''s Confidential Information (and independent development shall not be established merely by the receipt of similar information from a third party unless the Receiving Party can demonstrate independent creation); or\n\n(e) is expressly approved for release or disclosure in writing by an authorised representative of the Disclosing Party.\n\n3.2 Combination of information. Information shall not be deemed to fall within Clause 3.1 merely because individual elements are in the public domain, if the combination of those elements, or the manner in which they are compiled, is confidential.\n\n3.3 Burden of proof. The Receiving Party bears the burden of proving that information falls within an exclusion in this Clause 3.\n\n3.4 Statutory and public interest disclosures. Nothing in this Agreement is intended to restrict disclosures that are protected by law, including (without limitation) disclosures protected under:\n\n(a) the whistleblowing protections under the Employment Rights Act 1996 (as amended by the Public Interest Disclosure Act 1998) (to the extent applicable);\n\n(b) the Trade Secrets (Enforcement, etc.) Regulations 2018, including where disclosure is for the purpose of revealing misconduct, wrongdoing or illegal activity, provided that any applicable legal requirements are satisfied; or\n\n(c) any other non-excludable right to disclose information to a regulator, law enforcement agency, or other competent authority.\n\n3.5 No implied right to use. Any information falling within an exclusion under this Clause 3 may be used by the Receiving Party only to the extent such use does not infringe any intellectual property rights, contractual restrictions, data protection obligations, or other rights of the Disclosing Party or third parties."},{"id":"term_and_duration","type":"standard","order":4,"title":"4. TERM AND DURATION","content":"4.1 Commencement. This Agreement shall commence on the Effective Date.\n\n4.2 Term. Unless terminated earlier in accordance with Clause 4.3, this Agreement shall continue until the earlier of:\n\n(a) {{expiration_date}} (if completed); or\n\n(b) termination by either Party by giving the other Party not less than {{notice_period}} days'' written notice.\n\n4.3 Termination for cause. Either Party may terminate this Agreement immediately by written notice if the other Party commits a material breach of this Agreement which, if capable of remedy, is not remedied within 10 Business Days after written notice to do so.\n\n4.4 Survival.\n\n(a) The Receiving Party''s confidentiality and restricted use obligations in respect of Confidential Information disclosed during the term of this Agreement shall survive termination or expiry of this Agreement for {{confidentiality_period}} years from the date of disclosure of the relevant Confidential Information.\n\n(b) Notwithstanding Clause 4.4(a), in respect of any Confidential Information that is a Trade Secret, the obligations in this Agreement shall continue for so long as that information remains a Trade Secret under applicable law.\n\n4.5 Accrued rights. Termination or expiry of this Agreement shall not affect any accrued rights, remedies, obligations or liabilities of either Party that have accrued up to the date of termination or expiry.\n\n4.6 Continuing application to retained materials. Any Confidential Materials lawfully retained under Clause 5.3 shall remain subject to this Agreement for so long as they are retained."},{"id":"return_of_information","type":"standard","order":5,"title":"5. RETURN OR DESTRUCTION OF INFORMATION","content":"5.1 Trigger events. Upon the earlier of (i) written request by the Disclosing Party, or (ii) termination or expiry of this Agreement, the Receiving Party shall promptly (and in any event within {{return_destroy_period}} days) do one of the following at the Disclosing Party''s election:\n\n(a) return to the Disclosing Party all Confidential Materials (including all copies) in the Receiving Party''s possession or control; or\n\n(b) securely destroy or permanently delete all Confidential Materials (including all copies) from its systems and devices.\n\n5.2 Secure deletion. Where destruction or deletion is requested:\n\n(a) the Receiving Party shall use deletion methods appropriate to the media and risk (including, where appropriate, secure wiping) and shall take reasonable steps to ensure Confidential Information is not recoverable in the ordinary course;\n\n(b) where Confidential Information is held by Permitted Recipients, the Receiving Party shall procure that those Permitted Recipients comply with this Clause 5.\n\n5.3 Permitted retention.\n\n(a) Notwithstanding Clause 5.1, the Receiving Party may retain Confidential Materials to the extent required by applicable law, regulation, professional standards, court order, or a bona fide internal document retention and backup policy.\n\n(b) The Receiving Party may also retain one archival copy of Confidential Materials for the sole purpose of establishing the content and date of receipt of Confidential Information and/or for the purpose of defending or enforcing legal rights.\n\n(c) Any retained Confidential Materials shall remain subject to this Agreement, shall be securely stored, access restricted to those who need to know for the purpose of compliance with Clause 5.3, and shall not be used for any other purpose.\n\n5.4 Certification. Upon request, an authorised officer of the Receiving Party shall certify in writing compliance with this Clause 5, provided that the Receiving Party shall not be required to disclose details of its internal systems beyond what is reasonable.\n\n5.5 No obligation to return by email. The Disclosing Party may specify reasonable delivery requirements for returned materials (including secure file transfer or encrypted media). The Receiving Party shall not send Confidential Information by unencrypted email unless the Disclosing Party expressly agrees in writing.\n\n5.6 Samples and prototypes. Where the Disclosing Party provides prototypes, hardware, samples, or other tangible embodiments of Confidential Information, the Receiving Party shall keep them secure, not disassemble them (except as permitted by Clause 2.9(b)), and return them in accordance with Clause 5.1."},{"id":"data_protection","type":"standard","order":6,"title":"6. DATA PROTECTION","content":"6.1 General compliance. Each Party shall comply with Data Protection Legislation in connection with any Processing of Personal Data under or in connection with this Agreement.\n\n6.2 Nature of Processing. The Parties anticipate that Personal Data (if any) disclosed under this Agreement will typically be limited to business contact details and similar information shared for the Permitted Purpose, but may also include other categories depending on the Permitted Purpose.\n\n6.3 Controller roles.\n\n(a) Unless the Parties agree otherwise in writing, each Party acts as an independent Controller (as defined in the UK GDPR) in respect of any Personal Data it Processes under or in connection with this Agreement.\n\n(b) Nothing in this Agreement is intended to create a relationship of joint controllership. If the Parties consider that they are joint Controllers or that one Party is acting as Processor for the other, they shall agree a separate, compliant arrangement in writing (including, where applicable, a controller-to-controller data sharing arrangement or an Article 28 UK GDPR data processing agreement) before the relevant Processing takes place.\n\n6.4 Lawful basis and transparency.\n\n(a) Each Party shall ensure that it has a lawful basis under the UK GDPR to disclose and/or Process Personal Data for the Permitted Purpose.\n\n(b) Each Party is responsible for providing any required privacy information to individuals (including employees, contractors, and representatives) whose Personal Data it discloses to the other Party.\n\n6.5 Data minimisation and retention.\n\n(a) Each Party shall use reasonable endeavours to minimise the Personal Data disclosed and Processed under this Agreement.\n\n(b) Each Party shall not retain Personal Data received from the other Party for longer than necessary for the Permitted Purpose or to comply with law and legitimate record-keeping requirements, and shall securely delete or anonymise such Personal Data in accordance with Clause 5 where applicable.\n\n6.6 Security measures. Without limiting Clause 2.5, each Party shall implement appropriate technical and organisational measures to ensure a level of security appropriate to the risk, including as appropriate: access controls, encryption, resilience of systems, confidentiality training, and incident response procedures.\n\n6.7 International transfers. A Party shall not transfer Personal Data received from the other Party to a country outside the United Kingdom (or, where relevant, outside the scope of adequacy regulations under UK law) unless it has ensured appropriate safeguards are in place under the UK GDPR (for example, the UK International Data Transfer Agreement or Addendum, or other permitted mechanism) and has complied with any related requirements.\n\n6.8 Data subject requests and regulator engagement.\n\n(a) If a Party receives a request from an individual to exercise their rights under the UK GDPR (including subject access, erasure, restriction, or objection) and the request relates to Personal Data disclosed by the other Party, the receiving Party shall (to the extent permitted by law) promptly notify the other Party.\n\n(b) Each Party shall co-operate reasonably with the other Party in relation to such requests and any correspondence, enquiry, notice, investigation or enforcement action from the ICO or other competent authority relating to Processing under this Agreement.\n\n6.9 Personal data breaches.\n\n(a) Each Party shall notify the other Party without undue delay (and in any event within {{breach_notice_hours}} hours where reasonably practicable) upon becoming aware of a Personal Data breach (as defined in the UK GDPR) affecting Personal Data disclosed under this Agreement.\n\n(b) The notifying Party shall provide reasonable information to the other Party to allow it to comply with its obligations under Data Protection Legislation, including (where available) the categories and approximate number of affected individuals and records, the likely consequences, and measures taken or proposed to address the breach.\n\n6.10 No marketing unless agreed. Neither Party shall use Personal Data received under this Agreement for unsolicited direct marketing purposes, nor shall it send marketing communications in breach of PECR. Any marketing activities between the Parties shall be subject to separate agreement and appropriate consents or lawful bases.\n\n6.11 Order of precedence. If there is any conflict between this Clause 6 and any separate data processing or data sharing agreement entered into by the Parties, the separate agreement shall prevail to the extent of the conflict in relation to Personal Data Processing."},{"id":"remedies","type":"negotiable","order":7,"title":"7. REMEDIES","content":"7.1 Acknowledgement of irreparable harm. Each Party acknowledges that unauthorised use or disclosure of Confidential Information may cause the Disclosing Party immediate and irreparable harm, including loss of competitive advantage, loss of goodwill, and/or significant commercial damage, for which damages alone may be an inadequate remedy.\n\n7.2 Injunctive and equitable relief. Accordingly, the Disclosing Party shall be entitled (without prejudice to any other rights or remedies) to seek interim, interlocutory and/or final injunctive relief, specific performance and other equitable relief in respect of any breach or threatened breach of this Agreement.\n\n7.3 No requirement to prove actual loss. The Parties agree that, for the purpose of seeking injunctive relief, it may be impracticable to quantify losses, and the Disclosing Party shall not be required to prove actual loss as a precondition to obtaining such relief (subject to the discretion of the court).\n\n7.4 Cumulative remedies. The rights and remedies provided under this Agreement are cumulative and do not exclude any rights or remedies provided by law, including under the Trade Secrets (Enforcement, etc.) Regulations 2018.\n\n7.5 Mitigation and co-operation. The Parties shall act reasonably and in good faith to mitigate the effects of any breach, including by promptly co-operating on containment steps and corrective measures.\n\n7.6 Costs. Nothing in this Agreement limits the court''s discretion as to costs. The Parties acknowledge that a successful party in legal proceedings may seek recovery of its costs subject to applicable procedural rules."},{"id":"governing_law","type":"standard","order":8,"title":"8. GOVERNING LAW AND JURISDICTION","content":"8.1 Governing law. This Agreement and any dispute or claim arising out of or in connection with it (including non-contractual disputes or claims) shall be governed by and construed in accordance with the laws of England and Wales.\n\n8.2 Jurisdiction. Subject to Clause 8.3, the Parties irrevocably agree that the courts of England and Wales shall have exclusive jurisdiction to settle any dispute or claim arising out of or in connection with this Agreement (including non-contractual disputes or claims).\n\n8.3 Interim relief. Nothing in this Agreement shall prevent either Party from seeking interim or conservatory relief (including an injunction) in any court of competent jurisdiction, where such relief is necessary to protect Confidential Information or Trade Secrets.\n\n8.4 Service of proceedings. Each Party agrees that proceedings may be served on it at its address set out in the Preamble (or such other address notified in accordance with Clause 9.1). This Clause 8.4 does not affect any other method of service permitted by law."},{"id":"general_provisions","type":"standard","order":9,"title":"9. GENERAL PROVISIONS","content":"9.1 Notices.\n\n(a) Any notice or other communication given under or in connection with this Agreement shall be in writing and shall be delivered by hand, by pre-paid recorded delivery (or other next Business Day delivery service) or by email.\n\n(b) Notices shall be sent to the addresses and email addresses set out below (or such other details as a Party may notify to the other in accordance with this Clause 9.1):\n\n(i) Party A: {{party_a_address}}; Email: {{party_a_email}} (for the attention of {{party_a_name}}).\n\n(ii) Party B: {{party_b_address}}; Email: {{party_b_email}} (for the attention of {{party_b_name}}).\n\n(c) A notice shall be deemed received:\n\n(i) if delivered by hand, at the time the notice is left at the proper address;\n\n(ii) if sent by pre-paid recorded delivery or other next Business Day delivery service, at 9.00 am on the second Business Day after posting; or\n\n(iii) if sent by email, at the time of transmission provided that the sender does not receive a delivery failure notification, and provided further that notices served by email outside 9.00 am to 5.30 pm on a Business Day in the place of receipt shall be deemed received at 9.00 am on the next Business Day.\n\n(d) This Clause 9.1 does not apply to the service of legal proceedings or other documents in any legal action.\n\n9.2 No licence; no transfer of intellectual property.\n\n(a) All intellectual property rights in Confidential Information (and in any materials supplied by a Party) shall remain vested in the Disclosing Party or its licensors.\n\n(b) Except as expressly set out in this Agreement, no licence or other right is granted to the Receiving Party under any patent, copyright, database right, design right, trade mark, trade secret or other intellectual property right, whether by implication, estoppel or otherwise.\n\n9.3 No obligation to proceed; no exclusivity. Nothing in this Agreement:\n\n(a) obliges either Party to proceed with any transaction or relationship, or to enter into any further agreement; or\n\n(b) grants either Party any exclusive rights in connection with the Permitted Purpose.\n\n9.4 No warranty; accuracy and reliance.\n\n(a) Confidential Information is provided \"as is\" for evaluation purposes. To the maximum extent permitted by law, the Disclosing Party makes no representation, warranty or undertaking (express or implied) as to the accuracy, completeness, currency, merchantability, fitness for a particular purpose, or non-infringement of any Confidential Information.\n\n(b) The Receiving Party acknowledges that it is responsible for assessing and verifying Confidential Information and for forming its own views in relation to any proposed transaction.\n\n(c) Nothing in this Clause 9.4 limits liability for fraud or fraudulent misrepresentation.\n\n9.5 No partnership or agency. Nothing in this Agreement shall be construed as creating a partnership, joint venture, fiduciary relationship or agency relationship between the Parties, nor shall either Party have authority to bind the other.\n\n9.6 Third party rights. A person who is not a Party to this Agreement shall not have any rights to enforce any term of this Agreement under the Contracts (Rights of Third Parties) Act 1999.\n\n9.7 Assignment.\n\n(a) Neither Party may assign, novate, transfer, charge, subcontract or deal in any other manner with any of its rights or obligations under this Agreement without the prior written consent of the other Party.\n\n(b) Notwithstanding Clause 9.7(a), either Party may assign or novate this Agreement to an Affiliate or to a successor in connection with a bona fide reorganisation, merger, acquisition, or sale of all or substantially all of its assets, provided that the assigning Party gives written notice to the other Party and the assignee agrees in writing to be bound by the terms of this Agreement.\n\n9.8 Severability. If any provision or part-provision of this Agreement is or becomes invalid, illegal or unenforceable, it shall be deemed modified to the minimum extent necessary to make it valid, legal and enforceable. If such modification is not possible, the relevant provision or part-provision shall be deemed deleted. Any modification to or deletion of a provision or part-provision under this Clause 9.8 shall not affect the validity and enforceability of the rest of this Agreement.\n\n9.9 Waiver. No failure or delay by a Party to exercise any right or remedy provided under this Agreement or by law shall constitute a waiver of that or any other right or remedy. A waiver is only effective if given in writing and shall not be deemed a waiver of any subsequent breach.\n\n9.10 Variation. No variation of this Agreement shall be effective unless it is in writing and signed by (or on behalf of) each Party.\n\n9.11 Entire agreement. This Agreement constitutes the entire agreement between the Parties relating to its subject matter and supersedes and extinguishes all prior discussions, correspondence, negotiations, drafts, arrangements and understandings between them, whether written or oral, relating to that subject matter.\n\n9.12 Counterparts and electronic signatures.\n\n(a) This Agreement may be executed in any number of counterparts, each of which when executed shall constitute a duplicate original, but all the counterparts shall together constitute the one agreement.\n\n(b) This Agreement may be executed and delivered by electronic signature and/or by exchange of electronically signed counterparts. The Parties agree that such execution is intended to be legally binding and effective.\n\n(c) The Parties acknowledge the validity of electronic signatures under the Electronic Communications Act 2000 and applicable UK law and guidance, and agree not to challenge the admissibility of an electronically signed copy of this Agreement solely on the basis that it is in electronic form.\n\n9.13 Further assurance. Each Party shall, at its own cost, do (or procure the doing of) all such further acts and execute all such further documents as the other Party may reasonably require for the purpose of giving full effect to this Agreement.\n\n9.14 Rights and remedies. Except as expressly stated, the rights of the Parties under this Agreement are in addition to and not exclusive of any rights or remedies provided by law.\n\n9.15 No set-off. Each Party''s obligations under this Agreement are independent. Any right of set-off or counterclaim in respect of amounts allegedly due is excluded to the extent permitted by law.\n\n9.16 Governing language. If this Agreement is executed in more than one language, the English language version shall prevail to the extent of any inconsistency.\n\n9.17 Costs. Each Party shall bear its own costs and expenses incurred in connection with the negotiation, preparation and execution of this Agreement and the evaluation of the Permitted Purpose, unless otherwise agreed in writing."},{"id":"non_solicitation","type":"optional","order":10,"title":"10. NON-SOLICITATION (OPTIONAL)","content":"10.1 Scope. Subject to Clause 10.3, during the term of this Agreement and for a period of {{non_solicit_period_months}} months thereafter, neither Party shall, without the other Party''s prior written consent:\n\n(a) solicit or entice away, or attempt to solicit or entice away, any Restricted Person; or\n\n(b) employ, engage, or contract with any Restricted Person other than through a general recruitment campaign not specifically targeted at such person.\n\n10.2 \"Restricted Person\" means any person who is, at the relevant time, an employee, officer, or key contractor of the other Party (or its Affiliates) with whom the soliciting Party (or its Representatives) had material dealings in connection with the Permitted Purpose or who became known to the soliciting Party primarily as a result of disclosures made under this Agreement.\n\n10.3 Permitted activities. Clause 10.1 shall not be breached by:\n\n(a) recruitment resulting from general advertising or use of recruitment agencies not directed at specific individuals of the other Party; or\n\n(b) engaging a person who independently approaches the engaging Party without any direct or indirect solicitation.\n\n10.4 Reasonableness. The Parties agree that this Clause 10 is reasonable and necessary to protect legitimate business interests, including Confidential Information, workforce stability and business connections. If any restriction is held unreasonable but would be reasonable if amended, it shall apply with such modifications as the court considers necessary to make it enforceable.\n\n10.5 Separate remedies. A breach of this Clause 10 shall be treated as a breach of this Agreement and the remedies in Clause 7 shall apply."},{"id":"announcements_publicity_optional","type":"optional","order":11,"title":"11. ANNOUNCEMENTS, PUBLICITY AND USE OF NAMES (OPTIONAL)","content":"11.1 No announcements. Except as permitted by Clause 11.2, neither Party shall make or authorise any public announcement, press release, or public statement concerning:\n\n(a) the existence or subject matter of this Agreement;\n\n(b) the fact that discussions or negotiations are taking place between the Parties; or\n\n(c) the identity of the other Party,\n\nwithout the other Party''s prior written consent (not to be unreasonably withheld or delayed).\n\n11.2 Required statements. Clause 11.1 does not prevent a Party from making any announcement or filing required by applicable law, regulation, or the rules of any recognised stock exchange, provided that (to the extent legally permitted) the Party making the statement:\n\n(a) gives the other Party reasonable prior notice; and\n\n(b) consults with the other Party in good faith as to the form and content of the statement.\n\n11.3 Use of marks and case studies. Neither Party shall use the other Party''s trade marks, logos, brand names, or refer to the other Party in marketing materials, case studies, or customer references without prior written consent.\n\n11.4 No implied endorsement. Nothing in this Agreement creates any endorsement, partnership or sponsorship relationship, and neither Party shall represent otherwise."},{"id":"compliance_and_ethics","type":"standard","order":12,"title":"12. COMPLIANCE AND ETHICS","content":"12.1 Anti-bribery and corruption.\n\n(a) Each Party shall comply with all applicable anti-bribery and anti-corruption laws including the Bribery Act 2010.\n\n(b) Each Party represents and warrants that it has not offered, promised, given, requested, agreed to receive or accepted, and will not offer, promise, give, request, agree to receive or accept, any financial or other advantage to induce or reward improper performance in connection with the Permitted Purpose.\n\n(c) Each Party shall maintain, during the term of this Agreement, policies and procedures reasonably designed to ensure compliance with the Bribery Act 2010.\n\n12.2 Facilitation payments. Each Party shall not make, authorise or accept any facilitation payment (as that term is commonly understood) in connection with the Permitted Purpose.\n\n12.3 Sanctions and prohibited parties. Each Party represents that, to the best of its knowledge, neither it nor its directors or senior officers is subject to sanctions administered by the United Kingdom, the United Nations, the European Union or the United States, and that it will not use Confidential Information in a manner that would cause the other Party to breach applicable sanctions or export control laws.\n\n12.4 Modern slavery and human trafficking.\n\n(a) Where applicable to a Party (including where it is required to publish a statement under section 54 of the Modern Slavery Act 2015), that Party shall maintain policies and procedures intended to identify and mitigate risks of modern slavery and human trafficking in its business and supply chains.\n\n(b) Each Party shall not knowingly engage in any activity, practice or conduct that would constitute an offence under sections 1, 2 or 4 of the Modern Slavery Act 2015.\n\n12.5 Criminal Finances Act 2017 (failure to prevent facilitation of tax evasion). Each Party shall have in place reasonable prevention procedures designed to prevent the facilitation of tax evasion offences and shall not knowingly engage in conduct that would cause the other Party to be in breach of the Criminal Finances Act 2017.\n\n12.6 Compliance with policies on site. Where a Party''s Representatives attend the other Party''s premises or access its systems, they shall comply with the host Party''s reasonable security, health and safety, and compliance policies notified to them in advance.\n\n12.7 Termination for compliance breach. A material breach of this Clause 12 shall be deemed a material breach for the purposes of Clause 4.3.\n\n12.8 No limitation of statutory reporting. Nothing in this Clause 12 limits a Party''s right or obligation to report to law enforcement or a regulator, or to make a protected disclosure where applicable."},{"id":"ir35_off_payroll_optional","type":"optional","order":13,"title":"13. IR35 / OFF-PAYROLL WORKING AND STATUS (OPTIONAL)","content":"13.1 Context. The Parties anticipate that discussions under the Permitted Purpose may involve consideration of consultancy and/or contractor services. This Clause 13 applies only to the extent that, in connection with the Permitted Purpose, one Party (or its Affiliate) supplies or proposes to supply the services of an individual to the other Party (directly or via an intermediary).\n\n13.2 No employment relationship created by this Agreement. Nothing in this Agreement is intended to create, and shall not be construed as creating, any contract of employment, worker relationship, agency relationship or partnership between:\n\n(a) a Party and the other Party''s employees, contractors or consultants; or\n\n(b) either Party and any individual supplied by the other Party.\n\n13.3 Off-payroll working rules.\n\n(a) The Parties acknowledge that the off-payroll working rules (commonly referred to as \"IR35\") may apply where an individual provides services through an intermediary.\n\n(b) Each Party shall be responsible for assessing and complying with its obligations under applicable tax law, including (where applicable) Chapter 10, Part 2 of the Income Tax (Earnings and Pensions) Act 2003 and related regulations and guidance.\n\n(c) This Agreement does not constitute a determination of employment status for tax purposes, and neither Party relies on the other for such determination unless expressly agreed in a separate written contract.\n\n13.4 Information sharing. Where the Parties enter into a separate services arrangement that is within scope of the off-payroll working rules, each Party shall provide to the other, upon reasonable request, information reasonably required to facilitate compliance (including, where applicable, a status determination statement and reasons), subject always to confidentiality and Data Protection Legislation.\n\n13.5 No control. For the purposes of discussions and any evaluation activities under this Agreement, neither Party shall supervise, direct or control the day-to-day activities of the other Party''s personnel except to the extent necessary for security and compliance on premises.\n\n13.6 Taxes. Except as expressly agreed in a separate written contract, each Party is responsible for its own taxes and for ensuring that its personnel and intermediaries meet their tax obligations.\n\n13.7 Precedence. If the Parties enter into a separate agreement governing the supply of services, the terms of that separate agreement shall prevail over this Clause 13 to the extent of any inconsistency."}]'::jsonb,
  signature_block = 'IN WITNESS WHEREOF, the Parties have executed this Agreement as of {{signature_date}}.

