"category":"party_b","required":false,"description":"Legal entity name (e.g., Ltd/LLP/PLC)"},{"id":"party_b_company_number","type":"text","label":"Party B Company Number","token":"{{party_b_company_number}}","category":"party_b","required":false,"description":"Companies House registration number (if applicable)"},{"id":"party_b_title","type":"text","label":"Party B Signatory Title","token":"{{party_b_title}}","category":"party_b","required":false,"description":"Job title of Party B signatory"},{"id":"effective_date","type":"date","label":"Effective Date","token":"{{effective_date}}","category":"dates","required":true,"description":"Date this Agreement starts"},{"id":"expiration_date","type":"date","label":"Expiration Date","token":"{{expiration_date}}","category":"dates","required":false,"description":"Date this Agreement ends (if applicable)"},{"id":"signature_date","type":"date","label":"Signature Date","token":"{{signature_date}}","category":"dates","required":false,"description":"Date of signing"},{"id":"confidentiality_period","type":"number","label":"Confidentiality Period (years)","token":"{{confidentiality_period}}","category":"terms","required":false,"description":"Number of years confidentiality obligations survive for non-trade secret information"},{"id":"notice_period","type":"number","label":"Termination Notice Period (days)","token":"{{notice_period}}","category":"terms","required":false,"description":"Days'' notice to terminate the Agreement for convenience"},{"id":"return_destroy_period","type":"number","label":"Return/Destruction Period (days)","token":"{{return_destroy_period}}","category":"terms","required":false,"description":"Number of days to return or destroy Confidential Materials following request or termination"},{"id":"breach_notice_hours","type":"number","label":"Breach Notice (hours)","token":"{{breach_notice_hours}}","category":"terms","required":false,"description":"Target timeframe in hours for notifying the other Party of a personal data breach (where reasonably practicable)"},{"id":"non_solicit_period_months","type":"number","label":"Non-solicitation Period (months)","token":"{{non_solicit_period_months}}","category":"terms","required":false,"description":"Number of months the non-solicitation obligation applies after termination (if Clause 10 is used)"},{"id":"purpose","type":"textarea","label":"Purpose","token":"{{purpose}}","category":"terms","required":false,"description":"Purpose of the disclosures and discussions"}]'::jsonb,
