a","label":"Receiving Party Registered Address","token":"{{party_b_address}}","category":"party_b","required":true,"description":"Registered office or principal place of business"},{"id":"party_b_company","type":"text","label":"Receiving Party Organisation Name","token":"{{party_b_company}}","category":"party_b","required":true,"description":"Full legal name of the receiving organisation"},{"id":"party_b_company_number","type":"text","label":"Receiving Party Company Number","token":"{{party_b_company_number}}","category":"party_b","required":false,"description":"Companies House registration number (if applicable)"},{"id":"party_b_jurisdiction_of_incorporation","type":"text","label":"Receiving Party Jurisdiction of Incorporation","token":"{{party_b_jurisdiction_of_incorporation}}","category":"party_b","required":false,"description":"E.g., England and Wales"},{"id":"party_b_title","type":"text","label":"Receiving Party Signatory Title","token":"{{party_b_title}}","category":"party_b","required":false,"description":"Job title"},{"id":"effective_date","type":"date","label":"Effective Date","token":"{{effective_date}}","category":"dates","required":true,"description":"Date the agreement takes effect"},{"id":"expiration_date","type":"date","label":"Expiration Date","token":"{{expiration_date}}","category":"dates","required":false,"description":"Optional end date of the agreement"},{"id":"signature_date","type":"date","label":"Signature Date","token":"{{signature_date}}","category":"dates","required":false,"description":"Date of signing"},{"id":"confidentiality_period","type":"number","label":"Confidentiality Period (Years)","token":"{{confidentiality_period}}","category":"terms","required":false,"description":"Number of years confidentiality obligations apply (excluding Trade Secrets)"},{"id":"notice_period","type":"number","label":"Termination Notice Period (Days)","token":"{{notice_period}}","category":"terms","required":false,"description":"Days'' written notice to terminate for convenience"},{"id":"return_period_days","type":"number","label":"Return/Destruction Period (Days)","token":"{{return_period_days}}","category":"terms","required":false,"description":"Days to return or destroy Confidential Information after request/termination"},{"id":"purpose","type":"textarea","label":"Purpose","token":"{{purpose}}","category":"terms","required":true,"description":"Purpose for which Confidential Information is disclosed"},{"id":"notice_email_a","type":"email","label":"Disclosing Party Notice Email","token":"{{notice_email_a}}","category":"notices","required":false,"description":"Email for formal notices (can be same as party_a_email)"},{"id":"notice_email_b","type":"email","label":"Receiving Party Notice Email","token":"{{notice_email_b}}","category":"notices","required":false,"description":"Email for formal notices (can be same as party_b_email)"},{"id":"data_protection_contact_a","type":"text","label":"Disclosing Party Data Protection Contact","token":"{{data_protection_contact_a}}","category":"data_protection","required":false,"description":"Email or contact point for data protection matters"},{"id":"data_protection_contact_b","type":"text","label":"Receiving Party Data Protection Contact","token":"{{data_protection_contact_b}}","category":"data_protection","required":false,"description":"Email or contact point for data protection matters"},{"id":"personal_data_breach_notice_hours","type":"number","label":"Personal Data Breach Notice (Hours)","token":"{{personal_data_breach_notice_hours}}","category":"data_protection","required":false,"description":"Hours within which the Receiving Party must notify the Disclosing Party of a personal data breach"},{"id":"include_non_solicitation","type":"text","label":"Include Non-Solicitation Clause (yes/no)","token":"{{include_non_solicitation}}","category":"optional","required":false,"description":"Set to \"yes\" to include clause 7 restrictions"},{"id":"non_solicitation_period","type":"number","label":"Non-Solicitation Period (Months)","token":"{{non_solicitation_period}}","category":"optional","required":false,"description":"Duration of non-solicitation restrictions after termination"},{"id":"processing_subject_matter_and_duration","type":"textarea","label":"Annex 1: Subject Matter and Duration","token":"{{processing_subject_matter_and_duration}}","category":"data_protection","required":false,"description":"Describe subject matter and duration of processing (if clause 6.10 applies)"},{"id":"processing_types_of_personal_data","type":"textarea","label":"Annex 1: Types of Personal Data","token":"{{processing_types_of_personal_data}}","category":"data_protection","required":false,"description":"List types of personal data (if clause 6.10 applies)"},{"id":"processing_categories_of_data_subjects","type":"textarea","label":"Annex 1: Categories of Data Subjects","token":"{{processing_categories_of_data_subjects}}","category":"data_protection","required":false,"description":"List categories of data subjects (if clause 6.10 applies)"},{"id":"processing_special_category_data","type":"textarea","label":"Annex 1: Special Category Data","token":"{{processing_special_category_data}}","category":"data_protection","required":false,"description":"Specify any special category data (if clause 6.10 applies)"},{"id":"processing_locations","type":"textarea","label":"Annex 1: Processing Locations","token":"{{processing_locations}}","category":"data_protection","required":false,"description":"Where processing will take place (if clause 6.10 applies)"},{"id":"processing_subprocessors","type":"textarea","label":"Annex 1: Sub-processors","token":"{{processing_subprocessors}}","category":"data_protection","required":false,"description":"Authorised sub-processors (if any)"},{"id":"processing_toms_summary","type":"textarea","label":"Annex 1: TOMs Summary","token":"{{processing_toms_summary}}","category":"data_protection","required":false,"description":"Summary of technical and organisational measures"},{"id":"witness_name","type":"text","label":"Witness Name","token":"{{witness_name}}","category":"signing","required":false,"description":"Optional witness name"},{"id":"witness_address","type":"textarea","label":"Witness Address","token":"{{witness_address}}","category":"signing","required":false,"description":"Optional witness address"}]'::jsonb,
