Date: {{signature_date}}',
  placeholders = '[{"id":"party_a_email","type":"email","label":"Company Email","token":"{{party_a_email}}","category":"party_a","required":true,"autofillKey":"email","description":"Company contact email for notices and communications"},{"id":"party_a_name","type":"text","label":"Company Signatory Name","token":"{{party_a_name}}","category":"party_a","required":true,"autofillKey":"name","description":"Name of authorised signatory for the Company"},{"id":"party_a_address","type":"textarea","label":"Company Registered Office Address","token":"{{party_a_address}}","category":"party_a","required":true,"autofillKey":"address","description":"Registered office address of the Company"},{"id":"party_a_company","type":"text","label":"Company Legal Name","token":"{{party_a_company}}","category":"party_a","required":true,"autofillKey":"company_name","description":"Full legal name of the Company (e.g., Example Limited)"},{"id":"party_a_title","type":"text","label":"Company Signatory Title","token":"{{party_a_title}}","category":"party_a","required":false,"autofillKey":"job_title","description":"Title/position of the Company signatory (e.g., Director)"},{"id":"company_number","type":"text","label":"Company Number","token":"{{company_number}}","category":"party_a","required":true,"description":"Companies House registration number"},{"id":"party_b_email","type":"email","label":"Investor Email","token":"{{party_b_email}}","category":"party_b","required":true,"description":"Investor email address for notices and communications"},{"id":"party_b_name","type":"text","label":"Investor Name","token":"{{party_b_name}}","category":"party_b","required":true,"description":"Investor full legal name"},{"id":"party_b_address","type":"textarea","label":"Investor Address","token":"{{party_b_address}}","category":"party_b","required":true,"description":"Investor address"},{"id":"effective_date","type":"date","label":"Effective Date","token":"{{effective_date}}","category":"dates","required":true,"description":"Date the Agreement is entered into"},{"id":"signature_date","type":"date","label":"Signature Date","token":"{{signature_date}}","category":"dates","required":false,"description":"Date of execution (may be same as Effective Date)"},{"id":"investment_amount","type":"currency","label":"Subscription Amount","token":"{{investment_amount}}","category":"financial","required":true,"description":"Amount paid by the Investor to the Company under this Agreement"},{"id":"valuation_cap","type":"currency","label":"Valuation Cap","token":"{{valuation_cap}}","category":"financial","required":true,"description":"Maximum valuation used to calculate the Conversion Price"},{"id":"discount_rate","type":"number","label":"Discount Rate (%)","token":"{{discount_rate}}","category":"financial","required":true,"description":"Discount percentage (e.g., 20 for 20%)"},{"id":"qualifying_round_threshold","type":"currency","label":"Qualifying Financing Threshold","token":"{{qualifying_round_threshold}}","category":"financial","required":true,"description":"Minimum gross cash proceeds for a Qualifying Financing (excluding conversions)"},{"id":"bank_account_details","type":"textarea","label":"Company Bank Account Details","token":"{{bank_account_details}}","category":"financial","required":false,"description":"Bank account details for payment of the Subscription Amount"},{"id":"long_stop_date","type":"date","label":"Long-Stop Date","token":"{{long_stop_date}}","category":"dates","required":false,"description":"Date after which Investor may elect conversion or repayment if no conversion event has occurred"},{"id":"eis_seis_position","type":"textarea","label":"EIS/SEIS Position (Optional)","token":"{{eis_seis_position}}","category":"optional","required":false,"description":"Optional wording describing any agreed approach to EIS/SEIS advance assurance (no guarantee)"},{"id":"disclosure_letter_reference","type":"text","label":"Disclosure Letter Reference (Optional)","token":"{{disclosure_letter_reference}}","category":"optional","required":false,"description":"Reference to any disclosure letter or written disclosures provided by the Company"},{"id":"investor_entity_name","type":"text","label":"Investor Entity Name (Optional)","token":"{{investor_entity_name}}","category":"party_b","required":false,"description":"If the Investor is an entity, its legal name"},{"id":"investor_signatory_name","type":"text","label":"Investor Signatory Name (Optional)","token":"{{investor_signatory_name}}","category":"party_b","required":false,"description":"Name of the person signing on behalf of the Investor entity"},{"id":"investor_signatory_title","type":"text","label":"Investor Signatory Title (Optional)","token":"{{investor_signatory_title}}","category":"party_b","required":false,"description":"Title of the person signing on behalf of the Investor entity"}]'::jsonb,
