and Milestones","token":"{{deliverables_and_milestones}}","category":"project","required":false,"description":"List of deliverables, milestones, and dates/criteria"},{"id":"delivery_method_details","type":"textarea","label":"Delivery Method Details","token":"{{delivery_method_details}}","category":"project","required":false,"description":"Where/how deliverables are delivered (email, drive link, repository, etc.)"},{"id":"acceptance_period_days","type":"number","label":"Acceptance Period (Business Days)","token":"{{acceptance_period_days}}","category":"terms","required":false,"description":"Client review period in business days"},{"id":"client_primary_contact_name","type":"text","label":"Client Primary Contact Name","token":"{{client_primary_contact_name}}","category":"project","required":false,"description":"Client point of contact for project management"},{"id":"client_primary_contact_email","type":"email","label":"Client Primary Contact Email","token":"{{client_primary_contact_email}}","category":"project","required":false,"description":"Email for Client point of contact"},{"id":"fee_schedule","type":"textarea","label":"Fee Schedule","token":"{{fee_schedule}}","category":"financial","required":false,"description":"Optional fee schedule or rate card"},{"id":"payment_amount","type":"currency","label":"Fixed Fee Amount","token":"{{payment_amount}}","category":"financial","required":false,"description":"Total fixed fee"},{"id":"hourly_rate","type":"currency","label":"Hourly Rate","token":"{{hourly_rate}}","category":"financial","required":false,"description":"Hourly rate"},{"id":"billing_increment","type":"number","label":"Billing Increment (Minutes)","token":"{{billing_increment}}","category":"financial","required":false,"description":"Time increment for hourly billing (e.g., 15)"},{"id":"retainer_amount","type":"currency","label":"Retainer Amount","token":"{{retainer_amount}}","category":"financial","required":false,"description":"Optional retainer amount"},{"id":"retainer_due_date","type":"text","label":"Retainer Due Date","token":"{{retainer_due_date}}","category":"financial","required":false,"description":"When the retainer is due (e.g., upon execution)"},{"id":"invoice_delivery_email","type":"email","label":"Invoice Delivery Email","token":"{{invoice_delivery_email}}","category":"financial","required":false,"description":"Email address where Consultant sends invoices"},{"id":"invoice_frequency","type":"text","label":"Invoice Frequency","token":"{{invoice_frequency}}","category":"financial","required":false,"description":"e.g., monthly, upon milestone completion"},{"id":"invoice_due_days","type":"number","label":"Invoice Due Days","token":"{{invoice_due_days}}","category":"financial","required":false,"description":"Days after invoice receipt that payment is due"},{"id":"invoice_dispute_days","type":"number","label":"Invoice Dispute Window (Days)","token":"{{invoice_dispute_days}}","category":"financial","required":false,"description":"Days for Client to dispute invoice in writing"},{"id":"payment_method","type":"text","label":"Payment Method","token":"{{payment_method}}","category":"financial","required":false,"description":"e.g., ACH, wire, check"},{"id":"payment_destination_details","type":"textarea","label":"Payment Destination Details","token":"{{payment_destination_details}}","category":"financial","required":false,"description":"Where payment is sent (bank details, address, etc.)"},{"id":"late_interest_rate","type":"text","label":"Late Interest Rate","token":"{{late_interest_rate}}","category":"financial","required":false,"description":"Monthly interest rate for late undisputed payments (e.g., 1.5%)"},{"id":"expenses_cap","type":"currency","label":"Expense Cap","token":"{{expenses_cap}}","category":"financial","required":false,"description":"Maximum reimbursable expenses without prior approval"},{"id":"suspension_after_days","type":"number","label":"Suspension After Days","token":"{{suspension_after_days}}","category":"terms","required":false,"description":"Days after notice of non-payment before Consultant may suspend"},{"id":"notice_period","type":"number","label":"Termination Notice Period (Days)","token":"{{notice_period}}","category":"terms","required":false,"description":"Days notice for termination for convenience"},{"id":"termination_fee_terms","type":"textarea","label":"Early Termination Fee Terms","token":"{{termination_fee_terms}}","category":"terms","required":false,"description":"Optional early termination fee terms, if any"},{"id":"transition_assistance_days","type":"number","label":"Transition Assistance Days","token":"{{transition_assistance_days}}","category":"terms","required":false,"description":"Optional transition period after termination"},{"id":"confidentiality_years","type":"number","label":"Confidentiality Term (Years)","token":"{{confidentiality_years}}","category":"terms","required":false,"description":"Duration of confidentiality obligations after termination (trade secrets last as long as protected)"},{"id":"incident_notice_hours","type":"number","label":"Incident Notice Hours","token":"{{incident_notice_hours}}","category":"privacy","required":false,"description":"Hours within which Consultant must notify Client of a Data Incident"},{"id":"portfolio_restrictions","type":"textarea","label":"Portfolio Restrictions","token":"{{portfolio_restrictions}}","category":"terms","required":false,"description":"Any restrictions on Consultant portfolio use"},{"id":"insurance_limits","type":"text","label":"Insurance Limits","token":"{{insurance_limits}}","category":"terms","required":false,"description":"Optional minimum insurance limits (e.g., $1M per claim)"},{"id":"liability_carveouts","type":"textarea","label":"Liability Carveouts Selection","token":"{{liability_carveouts}}","category":"terms","required":false,"description":"Specify any agreed carve-outs (e.g., confidentiality/data breach cap exceptions)"},{"id":"claims_limitations_period_months","type":"number","label":"Claims Limitations Period (Months)","token":"{{claims_limitations_period_months}}","category":"terms","required":false,"description":"Optional contractual limitations period"},{"id":"ip_indemnity_exclusive_remedy","type":"text","label":"IP Indemnity Exclusive Remedy Flag","token":"{{ip_indemnity_exclusive_remedy}}","category":"terms","required":false,"description":"Set to indicate IP indemnity is exclusive remedy (optional)"},{"id":"non_solicit_months","type":"number","label":"Non-Solicit Duration (Months)","token":"{{non_solicit_months}}","category":"optional_restrictions","required":false,"description":"Duration for non-solicitation restrictions"},{"id":"include_non_compete","type":"text","label":"Include Non-Compete","token":"{{include_non_compete}}","category":"optional_restrictions","required":false,"description":"Set to include non-compete (highly optional and scrutinized in NY)"},{"id":"non_compete_months","type":"number","label":"Non-Compete Duration (Months)","token":"{{non_compete_months}}","category":"optional_restrictions","required":false,"description":"Non-compete duration if included"},{"id":"identified_competitors","type":"textarea","label":"Identified Competitors","token":"{{identified_competitors}}","category":"optional_restrictions","required":false,"description":"List of specific competitors for any non-compete"},{"id":"non_compete_geography","type":"text","label":"Non-Compete Geography","token":"{{non_compete_geography}}","category":"optional_restrictions","required":false,"description":"Geographic limitation for any non-compete"},{"id":"negotiation_days","type":"number","label":"Negotiation Days","token":"{{negotiation_days}}","category":"disputes","required":false,"description":"Days for good-faith negotiation before mediation/litigation"},{"id":"mediation_provider","type":"text","label":"Mediation Provider","token":"{{mediation_provider}}","category":"disputes","required":false,"description":"Mediation administrator/provider name"},{"id":"fee_shifting_selected","type":"text","label":"Fee Shifting Selected","token":"{{fee_shifting_selected}}","category":"disputes","required":false,"description":"Set to indicate prevailing party attorneys'' fees clause applies"},{"id":"jury_waiver_selected","type":"text","label":"Jury Waiver Selected","token":"{{jury_waiver_selected}}","category":"disputes","required":false,"description":"Set to indicate jury trial waiver applies"}]'::jsonb,
