ELECTRONIC SIGNATURES: The Parties agree that this Agreement may be executed and delivered by electronic signature and/or in electronic record form, and that such signatures and records will be binding under the New York Electronic Signatures and Records Act (ESRA) and the federal E-SIGN Act.',
  placeholders = '[{"id":"party_a_email","type":"email","label":"Hiring Party Email","token":"{{party_a_email}}","category":"party_a","required":true,"autofillKey":"email","description":"Hiring party email for notices and communications"},{"id":"party_a_name","type":"text","label":"Hiring Party Signatory Name","token":"{{party_a_name}}","category":"party_a","required":true,"autofillKey":"name","description":"Name of the person signing for Hiring Party"},{"id":"party_a_address","type":"textarea","label":"Hiring Party Address","token":"{{party_a_address}}","category":"party_a","required":true,"autofillKey":"address","description":"Hiring party mailing address (also used for FIFA contract requirement and notices)"},{"id":"party_a_company","type":"text","label":"Hiring Party Company/Name","token":"{{party_a_company}}","category":"party_a","required":true,"autofillKey":"company_name","description":"Legal name of hiring party"},{"id":"party_a_title","type":"text","label":"Hiring Party Signatory Title","token":"{{party_a_title}}","category":"party_a","required":false,"autofillKey":"job_title","description":"Title of the person signing for Hiring Party"},{"id":"party_b_email","type":"email","label":"Freelance Worker Email","token":"{{party_b_email}}","category":"party_b","required":true,"description":"Freelance worker email for notices and communications"},{"id":"party_b_name","type":"text","label":"Freelance Worker Name","token":"{{party_b_name}}","category":"party_b","required":true,"description":"Name of freelance worker / signatory"},{"id":"party_b_address","type":"textarea","label":"Freelance Worker Address","token":"{{party_b_address}}","category":"party_b","required":true,"description":"Freelance worker mailing address (also used for FIFA contract requirement and notices)"},{"id":"party_b_company","type":"text","label":"Freelance Worker Business Name","token":"{{party_b_company}}","category":"party_b","required":false,"description":"DBA or entity name of freelance worker, if any"},{"id":"effective_date","type":"date","label":"Effective Date","token":"{{effective_date}}","category":"dates","required":true,"description":"Agreement start date"},{"id":"expiration_date","type":"date","label":"Expiration Date","token":"{{expiration_date}}","category":"dates","required":false,"description":"Agreement end date, if any"},{"id":"signature_date","type":"date","label":"Signature Date","token":"{{signature_date}}","category":"dates","required":false,"description":"Date of signing"},{"id":"venue_county","type":"text","label":"Venue County (New York)","token":"{{venue_county}}","category":"legal","required":true,"description":"Specific New York county for exclusive venue (e.g., New York, Kings, Queens)"},{"id":"services_description","type":"textarea","label":"Services Description / SOW Summary","token":"{{services_description}}","category":"project","required":true,"description":"Description of services to be performed (FIFA-required element)"},{"id":"deliverables_description","type":"textarea","label":"Deliverables Description","token":"{{deliverables_description}}","category":"project","required":false,"description":"List/description of deliverables"},{"id":"acceptance_criteria","type":"textarea","label":"Acceptance Criteria (Optional)","token":"{{acceptance_criteria}}","category":"project","required":false,"description":"Objective acceptance criteria for deliverables"},{"id":"acceptance_period_days","type":"number","label":"Acceptance Review Period (Business Days)","token":"{{acceptance_period_days}}","category":"project","required":false,"description":"Business days for client to review and accept deliverables"},{"id":"project_timeline","type":"textarea","label":"Project Timeline (Optional)","token":"{{project_timeline}}","category":"project","required":false,"description":"High-level schedule, deadlines, or timeline"},{"id":"milestones","type":"textarea","label":"Milestones (Optional)","token":"{{milestones}}","category":"project","required":false,"description":"Milestones and milestone dates/payment triggers"},{"id":"delivery_method","type":"text","label":"Delivery Method","token":"{{delivery_method}}","category":"project","required":false,"description":"How deliverables will be delivered (e.g., email, Drive, GitHub)"},{"id":"notice_period","type":"number","label":"Termination Notice Period (Days)","token":"{{notice_period}}","category":"terms","required":false,"description":"Days notice for termination for convenience"},{"id":"client_delay_days","type":"number","label":"Client Delay Days (Suspension Trigger)","token":"{{client_delay_days}}","category":"terms","required":false,"description":"Days of missing client inputs before freelancer may suspend"},{"id":"revision_rounds_included","type":"number","label":"Included Revision Rounds","token":"{{revision_rounds_included}}","category":"project","required":false,"description":"Number of revision rounds included in fee"},{"id":"feedback_turnaround_days","type":"number","label":"Feedback Turnaround (Business Days)","token":"{{feedback_turnaround_days}}","category":"project","required":false,"description":"Business days for client feedback"},{"id":"expenses_cap","type":"currency","label":"Expense Cap (Optional)","token":"{{expenses_cap}}","category":"financial","required":false,"description":"Maximum reimbursable expenses allowed without additional approval"},{"id":"compensation_terms","type":"textarea","label":"Compensation Terms","token":"{{compensation_terms}}","category":"financial","required":true,"description":"Rate/method of compensation and total value (FIFA-required element)"},{"id":"payment_amount","type":"currency","label":"Project Fee (If Fixed)","token":"{{payment_amount}}","category":"financial","required":false,"description":"Fixed project fee"},{"id":"hourly_rate","type":"currency","label":"Hourly Rate (If Hourly)","token":"{{hourly_rate}}","category":"financial","required":false,"description":"Hourly billing rate"},{"id":"hourly_cap","type":"currency","label":"Hourly Not-to-Exceed Cap (Optional)","token":"{{hourly_cap}}","category":"financial","required":false,"description":"Maximum fees for hourly work unless increased by change order"},{"id":"deposit_amount","type":"currency","label":"Deposit/Retainer Amount (Optional)","token":"{{deposit_amount}}","category":"financial","required":false,"description":"Deposit/retainer to begin work"},{"id":"deposit_due_date","type":"date","label":"Deposit Due Date (Optional)","token":"{{deposit_due_date}}","category":"financial","required":false,"description":"Date deposit is due"},{"id":"invoice_frequency","type":"text","label":"Invoice Frequency","token":"{{invoice_frequency}}","category":"financial","required":false,"description":"How often invoices are issued (e.g., upon completion, monthly, per milestone)"},{"id":"payment_method","type":"text","label":"Payment Method","token":"{{payment_method}}","category":"financial","required":false,"description":"Payment method (e.g., ACH, check, wire)"},{"id":"payment_currency","type":"text","label":"Payment Currency","token":"{{payment_currency}}","category":"financial","required":false,"description":"Currency for payment (e.g., USD)"},{"id":"late_fee_terms","type":"textarea","label":"Late Fee Terms (Optional)","token":"{{late_fee_terms}}","category":"financial","required":false,"description":"Optional contractual late fee terms (not limiting statutory rights)"},{"id":"invoice_dispute_days","type":"number","label":"Invoice Dispute Window (Days)","token":"{{invoice_dispute_days}}","category":"financial","required":false,"description":"Days after invoice receipt to dispute in writing"},{"id":"confidentiality_period","type":"number","label":"Confidentiality Period (Years)","token":"{{confidentiality_period}}","category":"terms","required":false,"description":"Years confidentiality obligations survive (trade secrets survive as long as protected)"},{"id":"incident_notice_hours","type":"number","label":"Security Incident Notice (Hours)","token":"{{incident_notice_hours}}","category":"privacy","required":false,"description":"Hours within which freelancer should notify of a security incident"},{"id":"data_processing_addendum_reference","type":"text","label":"Data Processing Addendum Reference (Optional)","token":"{{data_processing_addendum_reference}}","category":"privacy","required":false,"description":"Reference/name of any separate data processing addendum"},{"id":"subcontracting_policy","type":"textarea","label":"Subcontracting Policy (Optional)","token":"{{subcontracting_policy}}","category":"terms","required":false,"description":"Whether subcontracting is allowed and whether consent is required"},{"id":"onsite_requirements","type":"textarea","label":"Onsite Requirements (Optional)","token":"{{onsite_requirements}}","category":"project","required":false,"description":"Any onsite work requirements, location, access, hours"},{"id":"rush_fee_terms","type":"textarea","label":"Rush Fee Terms (Optional)","token":"{{rush_fee_terms}}","category":"financial","required":false,"description":"Optional rush/expedite fee structure"},{"id":"portfolio_restrictions","type":"textarea","label":"Portfolio Restrictions (Optional)","token":"{{portfolio_restrictions}}","category":"ip","required":false,"description":"Any restrictions or conditions on portfolio display"},{"id":"non_disparagement_terms","type":"textarea","label":"Non-Disparagement Terms (Optional)","token":"{{non_disparagement_terms}}","category":"terms","required":false,"description":"Optional non-disparagement language"},{"id":"ai_usage_terms","type":"textarea","label":"AI Usage Terms (Optional)","token":"{{ai_usage_terms}}","category":"terms","required":false,"description":"Any restrictions/permissions regarding AI tools"},{"id":"cancellation_fee_terms","type":"textarea","label":"Cancellation/Kill Fee Terms (Optional)","token":"{{cancellation_fee_terms}}","category":"financial","required":false,"description":"Optional cancellation fee or kill fee terms"},{"id":"liability_cap_period","type":"number","label":"Liability Cap Lookback Period (Months)","token":"{{liability_cap_period}}","category":"legal","required":false,"description":"Months preceding claim for liability cap calculation"},{"id":"insurance_requirements","type":"textarea","label":"Insurance Requirements (Optional)","token":"{{insurance_requirements}}","category":"legal","required":false,"description":"Optional insurance requirements (types/limits/certificates)"},{"id":"negotiation_days","type":"number","label":"Negotiation Period (Days)","token":"{{negotiation_days}}","category":"disputes","required":false,"description":"Days for informal negotiation before escalation"},{"id":"mediation_terms","type":"textarea","label":"Mediation Terms (Optional)","token":"{{mediation_terms}}","category":"disputes","required":false,"description":"Optional mediation requirement details"},{"id":"mediation_location","type":"text","label":"Mediation Location (Optional)","token":"{{mediation_location}}","category":"disputes","required":false,"description":"City/county for mediation"},{"id":"jury_trial_waiver_terms","type":"textarea","label":"Jury Trial Waiver Terms (Optional)","token":"{{jury_trial_waiver_terms}}","category":"legal","required":false,"description":"Optional jury trial waiver language, if desired"},{"id":"non_compete_terms","type":"textarea","label":"Non-Compete Terms (Strongly Optional)","token":"{{non_compete_terms}}","category":"legal","required":false,"description":"Non-compete restrictions, if any (NY disfavored; should be narrow)"},{"id":"non_solicit_terms","type":"textarea","label":"Non-Solicitation Terms (Optional)","token":"{{non_solicit_terms}}","category":"legal","required":false,"description":"Optional non-solicitation clause details"},{"id":"no_hire_terms","type":"textarea","label":"No-Hire Terms (Optional)","token":"{{no_hire_terms}}","category":"legal","required":false,"description":"Optional no-hire restrictions, if any"},{"id":"indemnity_sole_remedy_terms","type":"textarea","label":"Indemnity Sole Remedy Terms (Optional)","token":"{{indemnity_sole_remedy_terms}}","category":"legal","required":false,"description":"If desired, specify whether IP indemnity is sole remedy"},{"id":"attachments_list","type":"textarea","label":"Attachments List (Optional)","token":"{{attachments_list}}","category":"terms","required":false,"description":"List of attachments/addenda incorporated into the agreement"}]'::jsonb,
