  placeholders = '[{"id":"party_a_email","type":"email","label":"Client Email","token":"{{party_a_email}}","category":"party_a","required":true,"autofillKey":"email","description":"Client notice email address"},{"id":"party_a_name","type":"text","label":"Client Signatory Name","token":"{{party_a_name}}","category":"party_a","required":true,"autofillKey":"name","description":"Full legal name of Client signatory"},{"id":"party_a_address","type":"textarea","label":"Client Address","token":"{{party_a_address}}","category":"party_a","required":true,"autofillKey":"address","description":"Client mailing address"},{"id":"party_a_company","type":"text","label":"Client Legal Name","token":"{{party_a_company}}","category":"party_a","required":true,"autofillKey":"company_name","description":"Client company legal name"},{"id":"party_a_title","type":"text","label":"Client Signatory Title","token":"{{party_a_title}}","category":"party_a","required":false,"autofillKey":"job_title","description":"Title of Client signatory"},{"id":"party_b_email","type":"email","label":"Contractor Email","token":"{{party_b_email}}","category":"party_b","required":true,"description":"Contractor notice email address"},{"id":"party_b_name","type":"text","label":"Contractor Signatory Name","token":"{{party_b_name}}","category":"party_b","required":true,"description":"Full legal name of Contractor signatory"},{"id":"party_b_address","type":"textarea","label":"Contractor Address","token":"{{party_b_address}}","category":"party_b","required":true,"description":"Contractor mailing address"},{"id":"party_b_company","type":"text","label":"Contractor Legal Name","token":"{{party_b_company}}","category":"party_b","required":true,"description":"Contractor company or individual legal name"},{"id":"party_b_title","type":"text","label":"Contractor Signatory Title","token":"{{party_b_title}}","category":"party_b","required":false,"description":"Title of Contractor signatory (if applicable)"},{"id":"effective_date","type":"date","label":"Effective Date","token":"{{effective_date}}","category":"dates","required":true,"description":"Agreement effective date"},{"id":"expiration_date","type":"date","label":"Expiration Date","token":"{{expiration_date}}","category":"dates","required":false,"description":"Agreement end date (if applicable)"},{"id":"signature_date","type":"date","label":"Signature Date","token":"{{signature_date}}","category":"dates","required":false,"description":"Date of signing"},{"id":"venue_county","type":"text","label":"Venue County","token":"{{venue_county}}","category":"terms","required":true,"description":"New York county for exclusive venue (e.g., New York, Kings, Queens)"},{"id":"notice_period","type":"number","label":"Termination Notice Period (Days)","token":"{{notice_period}}","category":"terms","required":false,"description":"Days'' notice for termination for convenience"},{"id":"hourly_rate","type":"currency","label":"Hourly Rate","token":"{{hourly_rate}}","category":"financial","required":false,"description":"Hourly rate, if applicable"},{"id":"payment_amount","type":"currency","label":"Fixed Fee Amount","token":"{{payment_amount}}","category":"financial","required":false,"description":"Fixed fee, if applicable"},{"id":"services_description","type":"textarea","label":"Services / SOW Description","token":"{{services_description}}","category":"project","required":true,"description":"Description of services, deliverables, milestones, and acceptance criteria"},{"id":"acceptance_period_days","type":"number","label":"Acceptance Period (Business Days)","token":"{{acceptance_period_days}}","category":"project","required":false,"description":"Client review/acceptance period if not specified in SOW"},{"id":"client_project_contact","type":"text","label":"Client Project Contact","token":"{{client_project_contact}}","category":"project","required":false,"description":"Name/role of Client point of contact"},{"id":"contractor_project_contact","type":"text","label":"Contractor Project Contact","token":"{{contractor_project_contact}}","category":"project","required":false,"description":"Name/role of Contractor point of contact"},{"id":"invoice_delivery_email","type":"email","label":"Invoice Submission Email","token":"{{invoice_delivery_email}}","category":"financial","required":false,"description":"Email address for invoice delivery"},{"id":"payment_due_terms","type":"textarea","label":"Payment Due Terms","token":"{{payment_due_terms}}","category":"financial","required":false,"description":"Payment due date or mechanism (e.g., Net 15 from invoice; or milestones)"},{"id":"invoice_dispute_days","type":"number","label":"Invoice Dispute Window (Days)","token":"{{invoice_dispute_days}}","category":"financial","required":false,"description":"Days for Client to dispute an invoice"},{"id":"late_interest_rate","type":"text","label":"Late Interest Rate","token":"{{late_interest_rate}}","category":"financial","required":false,"description":"Monthly interest rate for overdue undisputed amounts (if any)"},{"id":"payment_method","type":"text","label":"Payment Method","token":"{{payment_method}}","category":"financial","required":false,"description":"Method of payment (e.g., ACH, check)"},{"id":"expense_cap","type":"currency","label":"Expense Cap","token":"{{expense_cap}}","category":"financial","required":false,"description":"Maximum reimbursable expenses if allowed"},{"id":"retainer_amount","type":"currency","label":"Retainer/Deposit Amount","token":"{{retainer_amount}}","category":"financial","required":false,"description":"Retainer amount, if applicable"},{"id":"retainer_terms","type":"textarea","label":"Retainer Terms","token":"{{retainer_terms}}","category":"financial","required":false,"description":"How retainer is applied/refunded"},{"id":"transition_hours_cap","type":"number","label":"Transition Assistance Hours Cap","token":"{{transition_hours_cap}}","category":"terms","required":false,"description":"Maximum hours of transition assistance after termination"},{"id":"confidentiality_years","type":"number","label":"Confidentiality Term (Years)","token":"{{confidentiality_years}}","category":"legal","required":false,"description":"Years confidentiality applies for non-trade-secret information"},{"id":"security_notice_hours","type":"number","label":"Security Incident Notice (Hours)","token":"{{security_notice_hours}}","category":"privacy","required":false,"description":"Hours to notify Client after discovering a Security Incident"},{"id":"liability_cap_amount","type":"currency","label":"Liability Cap Amount","token":"{{liability_cap_amount}}","category":"legal","required":false,"description":"Total aggregate liability cap (if any)"},{"id":"prevailing_party_fees","type":"text","label":"Prevailing Party Attorneys'' Fees (yes/no)","token":"{{prevailing_party_fees}}","category":"legal","required":false,"description":"Whether prevailing party can recover attorneys'' fees for contract disputes (subject to law)"},{"id":"cgl_limit","type":"text","label":"CGL Per Occurrence Limit","token":"{{cgl_limit}}","category":"insurance","required":false,"description":"Commercial general liability per occurrence limit"},{"id":"cgl_aggregate","type":"text","label":"CGL Aggregate Limit","token":"{{cgl_aggregate}}","category":"insurance","required":false,"description":"Commercial general liability aggregate limit"},{"id":"eo_limit","type":"text","label":"E&O Limit","token":"{{eo_limit}}","category":"insurance","required":false,"description":"Professional liability / errors and omissions limit"},{"id":"cyber_limit","type":"text","label":"Cyber Liability Limit","token":"{{cyber_limit}}","category":"insurance","required":false,"description":"Cyber/privacy liability insurance limit"},{"id":"employers_liability_limit","type":"text","label":"Employer''s Liability Limit","token":"{{employers_liability_limit}}","category":"insurance","required":false,"description":"Employer''s liability limit"},{"id":"auto_limit","type":"text","label":"Auto Liability Limit","token":"{{auto_limit}}","category":"insurance","required":false,"description":"Automobile liability limit"},{"id":"non_solicit_enabled","type":"text","label":"Enable Non-Solicitation (yes/no)","token":"{{non_solicit_enabled}}","category":"optional","required":false,"description":"Whether to include non-solicitation restrictions"},{"id":"non_solicit_months","type":"number","label":"Non-Solicitation Duration (Months)","token":"{{non_solicit_months}}","category":"optional","required":false,"description":"Duration of non-solicitation restriction"},{"id":"publicity_allowed","type":"text","label":"Allow Publicity (yes/no)","token":"{{publicity_allowed}}","category":"optional","required":false,"description":"Whether parties may publicly reference each other"},{"id":"dispute_resolution_method","type":"text","label":"Dispute Resolution Method","token":"{{dispute_resolution_method}}","category":"legal","required":false,"description":"Leave blank for court; or set to ''mediation'' or ''arbitration''"},{"id":"arbitration_provider","type":"text","label":"Arbitration Provider","token":"{{arbitration_provider}}","category":"legal","required":false,"description":"Arbitration administrator (e.g., AAA, JAMS) if arbitration is selected"}]'::jsonb,
