,"required":false,"description":"When the agreement ends"},{"id":"signature_date","type":"date","label":"Signature Date","token":"{{signature_date}}","category":"dates","required":false,"description":"Date of signing"},{"id":"venue_county","type":"text","label":"Venue County","token":"{{venue_county}}","category":"terms","required":true,"description":"New York county for legal venue"},{"id":"confidentiality_period","type":"number","label":"Confidentiality Period","token":"{{confidentiality_period}}","category":"terms","required":false,"description":"Years of confidentiality obligation"},{"id":"notice_period","type":"number","label":"Notice Period","token":"{{notice_period}}","category":"terms","required":false,"description":"Days notice for termination"},{"id":"purpose","type":"textarea","label":"Purpose","token":"{{purpose}}","category":"terms","required":false,"description":"Purpose of the disclosure"},{"id":"security_notice_hours","type":"number","label":"Security Incident Notice (Hours)","token":"{{security_notice_hours}}","category":"terms","required":false,"description":"Number of hours within which the receiving party must notify of a security incident"},{"id":"return_destroy_days","type":"number","label":"Return/Destroy Deadline (Days)","token":"{{return_destroy_days}}","category":"terms","required":false,"description":"Number of days to return or destroy confidential information after request or termination"},{"id":"non_solicitation_period","type":"number","label":"Non-Solicitation Period (Months)","token":"{{non_solicitation_period}}","category":"terms","required":false,"description":"Duration of non-solicitation obligations in months (if Section 9 is elected)"}]'::jsonb,
