Date: {{signature_date}}',
  placeholders = '[{"id":"party_a_email","type":"email","label":"Disclosing Party Email","token":"{{party_a_email}}","category":"party_a","required":true,"autofillKey":"email","description":"Email address of the disclosing party"},{"id":"party_a_name","type":"text","label":"Disclosing Party Signer Name","token":"{{party_a_name}}","category":"party_a","required":true,"autofillKey":"name","description":"Full legal name of authorized signer"},{"id":"party_a_address","type":"textarea","label":"Disclosing Party Address","token":"{{party_a_address}}","category":"party_a","required":false,"autofillKey":"address","description":"Business or mailing address"},{"id":"party_a_company","type":"text","label":"Disclosing Party Company","token":"{{party_a_company}}","category":"party_a","required":false,"autofillKey":"company_name","description":"Legal entity name of disclosing party"},{"id":"party_a_title","type":"text","label":"Disclosing Party Signer Title","token":"{{party_a_title}}","category":"party_a","required":false,"autofillKey":"job_title","description":"Title of authorized signer"},{"id":"party_b_email","type":"email","label":"Receiving Party Email","token":"{{party_b_email}}","category":"party_b","required":true,"description":"Email address of the receiving party"},{"id":"party_b_name","type":"text","label":"Receiving Party Signer Name","token":"{{party_b_name}}","category":"party_b","required":true,"description":"Full legal name of authorized signer"},{"id":"party_b_address","type":"textarea","label":"Receiving Party Address","token":"{{party_b_address}}","category":"party_b","required":false,"description":"Business or mailing address"},{"id":"party_b_company","type":"text","label":"Receiving Party Company","token":"{{party_b_company}}","category":"party_b","required":false,"description":"Legal entity name of receiving party"},{"id":"party_b_title","type":"text","label":"Receiving Party Signer Title","token":"{{party_b_title}}","category":"party_b","required":false,"description":"Title of authorized signer"},{"id":"effective_date","type":"date","label":"Effective Date","token":"{{effective_date}}","category":"dates","required":true,"description":"Date the agreement becomes effective"},{"id":"expiration_date","type":"date","label":"Expiration Date","token":"{{expiration_date}}","category":"dates","required":false,"description":"Date the agreement ends, if any"},{"id":"signature_date","type":"date","label":"Signature Date","token":"{{signature_date}}","category":"dates","required":false,"description":"Date of signing"},{"id":"venue_county","type":"text","label":"Venue County (New York)","token":"{{venue_county}}","category":"terms","required":true,"description":"Specific New York county for exclusive venue (e.g., New York, Kings, Queens)"},{"id":"confidentiality_period","type":"number","label":"Confidentiality Period (Years)","token":"{{confidentiality_period}}","category":"terms","required":false,"description":"Number of years confidentiality obligations last for non-trade secrets"},{"id":"notice_period","type":"number","label":"Termination Notice Period (Days)","token":"{{notice_period}}","category":"terms","required":false,"description":"Days notice for termination of the agreement"},{"id":"purpose","type":"textarea","label":"Purpose","token":"{{purpose}}","category":"terms","required":false,"description":"Purpose of disclosure (e.g., evaluation of business relationship, project discussion)"},{"id":"security_incident_notice_hours","type":"number","label":"Security Incident Notice (Hours)","token":"{{security_incident_notice_hours}}","category":"privacy_security","required":false,"description":"Hours within which receiving party must notify disclosing party after becoming aware of a security incident"},{"id":"non_solicit_period_months","type":"number","label":"Non-Solicitation Period (Months) (Optional)","token":"{{non_solicit_period_months}}","category":"optional_terms","required":false,"description":"Duration for optional non-solicitation of employees covenant"},{"id":"services_description","type":"textarea","label":"Services Description (Optional)","token":"{{services_description}}","category":"freelance_optional","required":false,"description":"Description of services if this NDA doubles as a FIFAA-compliant written contract"},{"id":"services_completion_date","type":"date","label":"Services Completion Date (Optional)","token":"{{services_completion_date}}","category":"freelance_optional","required":false,"description":"Target completion date for services, if applicable"},{"id":"deliverables_description","type":"textarea","label":"Deliverables Description (Optional)","token":"{{deliverables_description}}","category":"freelance_optional","required":false,"description":"Deliverables to be provided, if any"},{"id":"compensation_amount","type":"text","label":"Compensation Amount (Optional)","token":"{{compensation_amount}}","category":"freelance_optional","required":false,"description":"Fee amount for services (e.g., $5,000)"},{"id":"invoice_email","type":"email","label":"Invoice Submission Email (Optional)","token":"{{invoice_email}}","category":"freelance_optional","required":false,"description":"Email address to send invoices to"},{"id":"payment_milestones","type":"textarea","label":"Payment Milestones (Optional)","token":"{{payment_milestones}}","category":"freelance_optional","required":false,"description":"Milestone payment schedule, if any"},{"id":"payment_method","type":"text","label":"Payment Method (Optional)","token":"{{payment_method}}","category":"freelance_optional","required":false,"description":"Payment method (e.g., ACH, check, wire)"},{"id":"expense_policy_summary","type":"textarea","label":"Expense Policy Summary (Optional)","token":"{{expense_policy_summary}}","category":"freelance_optional","required":false,"description":"Summary of reimbursable expenses and approval rules"},{"id":"privacy_contact_email","type":"email","label":"Privacy/Security Contact Email (Optional)","token":"{{privacy_contact_email}}","category":"privacy_security","required":false,"description":"Email address for privacy/security communications"}]'::jsonb,
