The Parties agree that this SAFE may be signed and delivered by electronic signature and electronic means and that such signatures will be binding under the New York Electronic Signatures and Records Act (ESRA) and the federal E-SIGN Act.',
  placeholders = '[{"id":"party_a_email","type":"email","label":"Company Email","token":"{{party_a_email}}","category":"party_a","required":true,"autofillKey":"email","description":"Company contact email"},{"id":"party_a_name","type":"text","label":"Company Signatory Name","token":"{{party_a_name}}","category":"party_a","required":true,"autofillKey":"name","description":"Name of company signatory"},{"id":"party_a_address","type":"textarea","label":"Company Address","token":"{{party_a_address}}","category":"party_a","required":true,"autofillKey":"address","description":"Company address"},{"id":"party_a_company","type":"text","label":"Company Legal Name","token":"{{party_a_company}}","category":"party_a","required":true,"autofillKey":"company_name","description":"Full company name"},{"id":"party_a_title","type":"text","label":"Company Signatory Title","token":"{{party_a_title}}","category":"party_a","required":false,"autofillKey":"job_title","description":"Title of signatory"},{"id":"entity_type","type":"text","label":"Company Entity Type","token":"{{entity_type}}","category":"party_a","required":true,"description":"Type of entity (corporation, LLC, etc.)"},{"id":"party_b_email","type":"email","label":"Investor Email","token":"{{party_b_email}}","category":"party_b","required":true,"description":"Investor email"},{"id":"party_b_name","type":"text","label":"Investor Name","token":"{{party_b_name}}","category":"party_b","required":true,"description":"Investor full legal name"},{"id":"party_b_address","type":"textarea","label":"Investor Address","token":"{{party_b_address}}","category":"party_b","required":true,"description":"Investor address"},{"id":"effective_date","type":"date","label":"Effective Date","token":"{{effective_date}}","category":"dates","required":true,"description":"SAFE effective date"},{"id":"signature_date","type":"date","label":"Signature Date","token":"{{signature_date}}","category":"dates","required":false,"description":"Date of signing"},{"id":"venue_county","type":"text","label":"Venue County","token":"{{venue_county}}","category":"terms","required":true,"description":"New York county for exclusive venue (e.g., New York, Kings, Queens)"},{"id":"investment_amount","type":"currency","label":"Purchase Amount","token":"{{investment_amount}}","category":"financial","required":true,"description":"Amount invested under the SAFE"},{"id":"valuation_cap","type":"currency","label":"Valuation Cap","token":"{{valuation_cap}}","category":"financial","required":true,"description":"Maximum valuation used to calculate conversion price"},{"id":"discount_rate","type":"number","label":"Discount Rate (%)","token":"{{discount_rate}}","category":"financial","required":true,"description":"Discount percentage (e.g., 20 for 20%)"},{"id":"qualifying_round_threshold","type":"currency","label":"Qualified Equity Financing Threshold","token":"{{qualifying_round_threshold}}","category":"financial","required":true,"description":"Minimum gross proceeds for an Equity Financing to qualify as a triggering event"}]'::jsonb,
