ys","token":"{{suspension_max_days}}","category":"project","required":false,"description":"Maximum days Client may suspend Services"},{"id":"client_poc_name","type":"text","label":"Client Point of Contact Name","token":"{{client_poc_name}}","category":"project","required":false,"description":"Client project contact person"},{"id":"client_poc_email","type":"email","label":"Client Point of Contact Email","token":"{{client_poc_email}}","category":"project","required":false,"description":"Client project contact email"},{"id":"consultant_poc_name","type":"text","label":"Consultant Point of Contact Name","token":"{{consultant_poc_name}}","category":"project","required":false,"description":"Consultant project contact person"},{"id":"consultant_poc_email","type":"email","label":"Consultant Point of Contact Email","token":"{{consultant_poc_email}}","category":"project","required":false,"description":"Consultant project contact email"},{"id":"confidentiality_years","type":"number","label":"Confidentiality Term (Years)","token":"{{confidentiality_years}}","category":"legal","required":false,"description":"Years confidentiality applies after termination (trade secrets indefinite)"},{"id":"security_incident_notice_hours","type":"number","label":"Security Incident Notice (Hours)","token":"{{security_incident_notice_hours}}","category":"security","required":false,"description":"Hours to notify after becoming aware of incident"},{"id":"restrict_data_location","type":"boolean","label":"Restrict Data Location","token":"{{restrict_data_location}}","category":"security","required":false,"description":"If true, restrict data processing locations"},{"id":"permitted_data_locations","type":"text","label":"Permitted Data Locations","token":"{{permitted_data_locations}}","category":"security","required":false,"description":"Permitted regions/countries/states for data storage/processing"},{"id":"require_dpa","type":"boolean","label":"Require DPA","token":"{{require_dpa}}","category":"security","required":false,"description":"If true, parties will sign a data processing addendum"},{"id":"enable_security_audit","type":"boolean","label":"Enable Security Audit Rights","token":"{{enable_security_audit}}","category":"security","required":false,"description":"If true, allow limited security questionnaires/audits"},{"id":"regulated_data_description","type":"textarea","label":"Regulated Data Description","token":"{{regulated_data_description}}","category":"security","required":false,"description":"Describe any regulated data involved (PHI, PCI, etc.)"},{"id":"liability_cap_lookback_months","type":"number","label":"Liability Cap Lookback (Months)","token":"{{liability_cap_lookback_months}}","category":"legal","required":false,"description":"Lookback period for liability cap calculation"},{"id":"data_liability_cap_amount","type":"currency","label":"Data Incident Liability Cap (Optional)","token":"{{data_liability_cap_amount}}","category":"legal","required":false,"description":"Optional separate cap for privacy/security incidents"},{"id":"claims_limitations_months","type":"number","label":"Claims Limitation Period (Months)","token":"{{claims_limitations_months}}","category":"legal","required":false,"description":"Contractual limitations period (if permitted)"},{"id":"enable_restrictive_covenants","type":"boolean","label":"Enable Restrictive Covenants","token":"{{enable_restrictive_covenants}}","category":"optional","required":false,"description":"If true, Section 13 applies"},{"id":"noncompete_term_months","type":"number","label":"Non-Compete Term (Months)","token":"{{noncompete_term_months}}","category":"optional","required":false,"description":"Duration of post-termination non-compete"},{"id":"noncompete_geography","type":"text","label":"Non-Compete Geography","token":"{{noncompete_geography}}","category":"optional","required":false,"description":"Geographic area for restriction"},{"id":"restricted_business_description","type":"textarea","label":"Restricted Business Description","token":"{{restricted_business_description}}","category":"optional","required":false,"description":"Define competing business activities"},{"id":"nohire_term_months","type":"number","label":"No-Hire / Non-Solicit Term (Months)","token":"{{nohire_term_months}}","category":"optional","required":false,"description":"Duration of no-hire / non-solicit"},{"id":"require_mediation","type":"boolean","label":"Require Mediation","token":"{{require_mediation}}","category":"disputes","required":false,"description":"If true, mediation is required before litigation (except injunctions)"},{"id":"prevailing_party_fees","type":"boolean","label":"Prevailing Party Attorneys'' Fees","token":"{{prevailing_party_fees}}","category":"disputes","required":false,"description":"If true, prevailing party may recover fees/costs"},{"id":"waive_exemplary_damages_contract","type":"boolean","label":"Waive Exemplary Damages for Contract Claims","token":"{{waive_exemplary_damages_contract}}","category":"legal","required":false,"description":"If true, waive punitive damages for pure contract claims (where permitted)"},{"id":"require_background_checks","type":"boolean","label":"Require Background Checks","token":"{{require_background_checks}}","category":"optional","required":false,"description":"If true, Consultant screens personnel as permitted by law"},{"id":"require_insurance","type":"boolean","label":"Require Insurance","token":"{{require_insurance}}","category":"optional","required":false,"description":"If true, Consultant maintains specified insurance"},{"id":"cgl_limit","type":"currency","label":"CGL Limit","token":"{{cgl_limit}}","category":"optional","required":false,"description":"Commercial general liability per occurrence limit"},{"id":"e_o_limit","type":"currency","label":"E&O Limit","token":"{{e_o_limit}}","category":"optional","required":false,"description":"Professional liability/E&O limit"},{"id":"cyber_limit","type":"currency","label":"Cyber Liability Limit","token":"{{cyber_limit}}","category":"optional","required":false,"description":"Cyber/privacy liability limit"},{"id":"enable_transition_assistance","type":"boolean","label":"Enable Transition Assistance","token":"{{enable_transition_assistance}}","category":"optional","required":false,"description":"If true, consultant provides limited transition support"},{"id":"transition_hours","type":"number","label":"Transition Assistance Hours","token":"{{transition_hours}}","category":"optional","required":false,"description":"Number of hours of transition assistance"},{"id":"allow_portfolio_use","type":"boolean","label":"Allow Portfolio Use","token":"{{allow_portfolio_use}}","category":"optional","required":false,"description":"If true, allow limited marketing references subject to approval"},{"id":"party_a_notice_name","type":"text","label":"Client Notice Recipient Name","token":"{{party_a_notice_name}}","category":"notices","required":false,"description":"Name/role for formal notices to Client"},{"id":"party_a_notice_address","type":"textarea","label":"Client Notice Address","token":"{{party_a_notice_address}}","category":"notices","required":false,"description":"Address for formal notices to Client"},{"id":"party_a_notice_email","type":"email","label":"Client Notice Email","token":"{{party_a_notice_email}}","category":"notices","required":false,"description":"Email for formal notices to Client"},{"id":"party_b_notice_name","type":"text","label":"Consultant Notice Recipient Name","token":"{{party_b_notice_name}}","category":"notices","required":false,"description":"Name/role for formal notices to Consultant"},{"id":"party_b_notice_address","type":"textarea","label":"Consultant Notice Address","token":"{{party_b_notice_address}}","category":"notices","required":false,"description":"Address for formal notices to Consultant"},{"id":"party_b_notice_email","type":"email","label":"Consultant Notice Email","token":"{{party_b_notice_email}}","category":"notices","required":false,"description":"Email for formal notices to Consultant"},{"id":"confidentiality_of_agreement","type":"boolean","label":"Confidentiality of Agreement","token":"{{confidentiality_of_agreement}}","category":"optional","required":false,"description":"If true, contract terms treated as Confidential Information"},{"id":"client_policy_applicable","type":"boolean","label":"Client Policies Applicable","token":"{{client_policy_applicable}}","category":"optional","required":false,"description":"If true, consultant must follow written contractor policies"},{"id":"enable_non_disparagement","type":"boolean","label":"Enable Non-Disparagement","token":"{{enable_non_disparagement}}","category":"optional","required":false,"description":"If true, non-disparagement applies"},{"id":"non_disparagement_term_months","type":"number","label":"Non-Disparagement Term (Months)","token":"{{non_disparagement_term_months}}","category":"optional","required":false,"description":"Duration of non-disparagement post-termination"}]'::jsonb,
