  placeholders = '[{"id":"party_a_email","type":"email","label":"Hiring Party Email","token":"{{party_a_email}}","category":"party_a","required":true,"autofillKey":"email","description":"Hiring party email for notices and communications"},{"id":"party_a_name","type":"text","label":"Hiring Party Signatory Name","token":"{{party_a_name}}","category":"party_a","required":true,"autofillKey":"name","description":"Name of the person signing for Hiring Party"},{"id":"party_a_address","type":"textarea","label":"Hiring Party Address","token":"{{party_a_address}}","category":"party_a","required":false,"autofillKey":"address","description":"Hiring party notice address"},{"id":"party_a_company","type":"text","label":"Hiring Party Company","token":"{{party_a_company}}","category":"party_a","required":false,"autofillKey":"company_name","description":"Legal name of Hiring Party"},{"id":"party_a_title","type":"text","label":"Hiring Party Signatory Title","token":"{{party_a_title}}","category":"party_a","required":false,"autofillKey":"job_title","description":"Title of the person signing for Hiring Party"},{"id":"party_b_email","type":"email","label":"Freelancer Email","token":"{{party_b_email}}","category":"party_b","required":true,"description":"Freelancer email for notices and communications"},{"id":"party_b_name","type":"text","label":"Freelancer Name","token":"{{party_b_name}}","category":"party_b","required":true,"description":"Name of the individual freelancer / signatory"},{"id":"party_b_address","type":"textarea","label":"Freelancer Address","token":"{{party_b_address}}","category":"party_b","required":false,"description":"Freelancer notice address"},{"id":"party_b_company","type":"text","label":"Freelancer Business Name","token":"{{party_b_company}}","category":"party_b","required":false,"description":"DBA or business name of freelancer"},{"id":"effective_date","type":"date","label":"Effective Date","token":"{{effective_date}}","category":"dates","required":true,"description":"Agreement effective date"},{"id":"expiration_date","type":"date","label":"Expiration Date","token":"{{expiration_date}}","category":"dates","required":false,"description":"Optional end date for the agreement"},{"id":"signature_date","type":"date","label":"Signature Date","token":"{{signature_date}}","category":"dates","required":false,"description":"Date of signing"},{"id":"venue_county","type":"text","label":"Texas Venue County","token":"{{venue_county}}","category":"terms","required":true,"description":"Texas county for exclusive venue"},{"id":"federal_district","type":"text","label":"Federal District Court (If Applicable)","token":"{{federal_district}}","category":"terms","required":false,"description":"U.S. District Court district/division covering the selected county (e.g., Southern District of Texas)"},{"id":"notice_period","type":"number","label":"Termination Notice Period (Days)","token":"{{notice_period}}","category":"terms","required":false,"description":"Days notice for termination for convenience"},{"id":"confidentiality_period","type":"number","label":"Confidentiality Period (Years)","token":"{{confidentiality_period}}","category":"terms","required":false,"description":"Years confidentiality obligations continue after termination (trade secrets may last longer)"},{"id":"hourly_rate","type":"currency","label":"Hourly Rate","token":"{{hourly_rate}}","category":"financial","required":false,"description":"Hourly rate for hourly work or out-of-scope work"},{"id":"payment_amount","type":"currency","label":"Fixed Project Fee","token":"{{payment_amount}}","category":"financial","required":false,"description":"Total fixed project fee"},{"id":"services_description","type":"textarea","label":"Services / Scope Description","token":"{{services_description}}","category":"project","required":false,"description":"Description of services, deliverables, and any special terms"},{"id":"project_name","type":"text","label":"Project Name","token":"{{project_name}}","category":"project","required":false,"description":"Short name of the project"},{"id":"statement_of_work_title","type":"text","label":"Statement of Work Title/Reference","token":"{{statement_of_work_title}}","category":"project","required":false,"description":"Identifier for the SOW, proposal, or scope document (if any)"},{"id":"acceptance_period_days","type":"number","label":"Acceptance Period (Days)","token":"{{acceptance_period_days}}","category":"project","required":false,"description":"Days the client has to accept or reject a deliverable"},{"id":"milestone_schedule","type":"textarea","label":"Milestone Schedule","token":"{{milestone_schedule}}","category":"project","required":false,"description":"Milestones, dates, and milestone payments if applicable"},{"id":"client_contact_name","type":"text","label":"Client Point of Contact Name","token":"{{client_contact_name}}","category":"project","required":false,"description":"Client representative authorized for approvals"},{"id":"client_contact_email","type":"email","label":"Client Point of Contact Email","token":"{{client_contact_email}}","category":"project","required":false,"description":"Email for client approvals and instructions"},{"id":"invoice_frequency","type":"text","label":"Invoice Frequency","token":"{{invoice_frequency}}","category":"financial","required":false,"description":"e.g., weekly, biweekly, monthly, upon milestones, upon completion"},{"id":"invoice_due_days","type":"number","label":"Invoice Due Days","token":"{{invoice_due_days}}","category":"financial","required":false,"description":"Net payment terms in days"},{"id":"payment_method","type":"text","label":"Payment Method","token":"{{payment_method}}","category":"financial","required":false,"description":"e.g., ACH, check, wire, payment processor"},{"id":"late_interest_rate","type":"number","label":"Late Interest Rate (Percent per Month)","token":"{{late_interest_rate}}","category":"financial","required":false,"description":"Monthly interest rate on late undisputed amounts, subject to Texas law"},{"id":"retainer_amount","type":"currency","label":"Retainer Amount","token":"{{retainer_amount}}","category":"financial","required":false,"description":"Optional retainer amount"},{"id":"deposit_amount","type":"currency","label":"Deposit Amount","token":"{{deposit_amount}}","category":"financial","required":false,"description":"Optional upfront deposit amount"},{"id":"deposit_percentage","type":"number","label":"Deposit Percentage","token":"{{deposit_percentage}}","category":"financial","required":false,"description":"Optional upfront deposit percentage"},{"id":"expense_cap_amount","type":"currency","label":"Expense Cap Amount","token":"{{expense_cap_amount}}","category":"financial","required":false,"description":"Maximum reimbursable expenses without additional approval"},{"id":"included_revision_rounds","type":"number","label":"Included Revision Rounds","token":"{{included_revision_rounds}}","category":"project","required":false,"description":"Number of revision rounds included in base fees"},{"id":"insurance_requirements","type":"textarea","label":"Insurance Requirements","token":"{{insurance_requirements}}","category":"terms","required":false,"description":"Optional insurance types/limits (e.g., GL, E&O, cyber)"},{"id":"portfolio_allowed","type":"text","label":"Portfolio Allowed (yes/no)","token":"{{portfolio_allowed}}","category":"terms","required":false,"description":"Whether the freelancer may display work in a portfolio"},{"id":"liability_cap_period","type":"number","label":"Liability Cap Lookback Period (Months)","token":"{{liability_cap_period}}","category":"terms","required":false,"description":"Months used to calculate fees paid/payable for liability cap"},{"id":"liability_cap_amount","type":"currency","label":"Liability Cap Amount (Floor)","token":"{{liability_cap_amount}}","category":"terms","required":false,"description":"Minimum liability cap amount, if any"},{"id":"early_termination_fee","type":"currency","label":"Early Termination Fee (Kill Fee)","token":"{{early_termination_fee}}","category":"financial","required":false,"description":"Optional kill fee payable upon early termination for convenience"},{"id":"non_solicit_term_months","type":"number","label":"Non-Solicitation Term (Months)","token":"{{non_solicit_term_months}}","category":"restrictive_covenants","required":false,"description":"Months non-solicitation applies after termination (if enabled)"},{"id":"non_compete_term_months","type":"number","label":"Non-Compete Term (Months)","token":"{{non_compete_term_months}}","category":"restrictive_covenants","required":false,"description":"Months non-compete applies after termination (if enabled)"},{"id":"non_compete_geography","type":"text","label":"Non-Compete Geography","token":"{{non_compete_geography}}","category":"restrictive_covenants","required":false,"description":"Geographic scope for non-compete (if enabled)"},{"id":"non_compete_scope_of_business","type":"text","label":"Restricted Business Scope","token":"{{non_compete_scope_of_business}}","category":"restrictive_covenants","required":false,"description":"Description of restricted business activities (if enabled)"},{"id":"non_disparagement_term_months","type":"number","label":"Non-Disparagement Term (Months)","token":"{{non_disparagement_term_months}}","category":"restrictive_covenants","required":false,"description":"Months non-disparagement applies after termination (if enabled)"},{"id":"dispute_resolution_section_number","type":"text","label":"Dispute Resolution Section Number Reference","token":"{{dispute_resolution_section_number}}","category":"terms","required":false,"description":"Reference number used if enabling the optional dispute resolution clause within Section 20"},{"id":"mediation_city","type":"text","label":"Mediation City (Texas)","token":"{{mediation_city}}","category":"dispute_resolution","required":false,"description":"City for mediation, if used"},{"id":"mediation_provider","type":"text","label":"Mediation Provider","token":"{{mediation_provider}}","category":"dispute_resolution","required":false,"description":"Mediation provider or rules, if used"},{"id":"arbitration_city","type":"text","label":"Arbitration City (Texas)","token":"{{arbitration_city}}","category":"dispute_resolution","required":false,"description":"City for arbitration, if enabled"},{"id":"arbitration_provider","type":"text","label":"Arbitration Provider","token":"{{arbitration_provider}}","category":"dispute_resolution","required":false,"description":"Arbitration provider (e.g., AAA), if enabled"}]'::jsonb,
