"id":"party_b_company","type":"text","label":"Contractor Company","token":"{{party_b_company}}","category":"party_b","required":true,"description":"Legal name of Contractor entity (or individual name if sole proprietor)"},{"id":"party_b_title","type":"text","label":"Contractor Signatory Title","token":"{{party_b_title}}","category":"party_b","required":false,"description":"Title of Contractor signatory"},{"id":"party_b_entity_type","type":"text","label":"Contractor Entity Type","token":"{{party_b_entity_type}}","category":"party_b","required":false,"description":"e.g., individual, LLC, corporation"},{"id":"party_b_state_of_formation","type":"text","label":"Contractor State of Formation","token":"{{party_b_state_of_formation}}","category":"party_b","required":false,"description":"State where Contractor is organized"},{"id":"effective_date","type":"date","label":"Effective Date","token":"{{effective_date}}","category":"dates","required":true,"description":"Effective date of the Agreement"},{"id":"expiration_date","type":"date","label":"Expiration Date","token":"{{expiration_date}}","category":"dates","required":false,"description":"End date of the Agreement term, if any"},{"id":"signature_date","type":"date","label":"Signature Date","token":"{{signature_date}}","category":"dates","required":false,"description":"Date of signing"},{"id":"venue_county","type":"text","label":"Venue County (Texas)","token":"{{venue_county}}","category":"terms","required":true,"description":"Texas county for exclusive venue"},{"id":"federal_district","type":"text","label":"Federal District (Texas)","token":"{{federal_district}}","category":"terms","required":false,"description":"e.g., Northern, Southern, Eastern, Western (District of Texas)"},{"id":"notice_period","type":"number","label":"Termination Notice Period (Days)","token":"{{notice_period}}","category":"terms","required":false,"description":"Days notice for termination for convenience"},{"id":"cure_period_days","type":"number","label":"Cure Period (Days)","token":"{{cure_period_days}}","category":"terms","required":false,"description":"Days to cure a material breach before termination for cause"},{"id":"deliverables_acceptance_days","type":"number","label":"Acceptance Period (Business Days)","token":"{{deliverables_acceptance_days}}","category":"project","required":false,"description":"Business days for Client to accept/reject deliverables"},{"id":"transition_assistance_days","type":"number","label":"Transition Assistance Days","token":"{{transition_assistance_days}}","category":"project","required":false,"description":"Days of optional transition assistance after termination"},{"id":"hourly_rate","type":"currency","label":"Hourly Rate","token":"{{hourly_rate}}","category":"financial","required":false,"description":"Rate per hour (if applicable)"},{"id":"payment_amount","type":"currency","label":"Fixed Fee / Total Fee","token":"{{payment_amount}}","category":"financial","required":false,"description":"Total or fixed fee (if applicable)"},{"id":"payment_terms_days","type":"number","label":"Payment Terms (Days)","token":"{{payment_terms_days}}","category":"financial","required":false,"description":"Days after receipt of invoice for payment (e.g., 30)"},{"id":"invoice_dispute_days","type":"number","label":"Invoice Dispute Period (Days)","token":"{{invoice_dispute_days}}","category":"financial","required":false,"description":"Days to dispute an invoice"},{"id":"late_fee_percent","type":"number","label":"Late Fee Interest Rate (% per month)","token":"{{late_fee_percent}}","category":"financial","required":false,"description":"Monthly interest rate for late payments (subject to law)"},{"id":"expense_reimbursement_policy","type":"text","label":"Expense Reimbursement Policy Reference","token":"{{expense_reimbursement_policy}}","category":"financial","required":false,"description":"Reference or link/name of reimbursement policy"},{"id":"records_retention_years","type":"number","label":"Records Retention (Years)","token":"{{records_retention_years}}","category":"terms","required":false,"description":"Years Contractor must retain invoice support records"},{"id":"services_description","type":"textarea","label":"Services Description / SOW Scope","token":"{{services_description}}","category":"project","required":true,"description":"Description of services, deliverables, milestones, and acceptance criteria"},{"id":"project_name","type":"text","label":"Project Name","token":"{{project_name}}","category":"project","required":false,"description":"Optional project name for invoices and reporting"},{"id":"client_rep_name","type":"text","label":"Client Project Contact Name","token":"{{client_rep_name}}","category":"project","required":false,"description":"Client point of contact"},{"id":"client_rep_email","type":"email","label":"Client Project Contact Email","token":"{{client_rep_email}}","category":"project","required":false,"description":"Client point of contact email"},{"id":"contractor_rep_name","type":"text","label":"Contractor Project Contact Name","token":"{{contractor_rep_name}}","category":"project","required":false,"description":"Contractor point of contact"},{"id":"contractor_rep_email","type":"email","label":"Contractor Project Contact Email","token":"{{contractor_rep_email}}","category":"project","required":false,"description":"Contractor point of contact email"},{"id":"confidentiality_term_years","type":"number","label":"Confidentiality Term (Years)","token":"{{confidentiality_term_years}}","category":"terms","required":false,"description":"Years confidentiality obligations apply after termination (trade secrets excluded)"},{"id":"data_breach_notice_hours","type":"number","label":"Data Breach Notice (Hours)","token":"{{data_breach_notice_hours}}","category":"privacy","required":false,"description":"Hours within which Contractor must notify Client after becoming aware of a Security Incident"},{"id":"liability_cap_amount","type":"currency","label":"Liability Cap Amount","token":"{{liability_cap_amount}}","category":"legal","required":false,"description":"Maximum aggregate liability cap (if used)"},{"id":"liability_cap_multiplier","type":"number","label":"Liability Cap Multiplier","token":"{{liability_cap_multiplier}}","category":"legal","required":false,"description":"Multiplier of fees for liability cap (if used)"},{"id":"general_liability_limit","type":"currency","label":"General Liability Limit","token":"{{general_liability_limit}}","category":"insurance","required":false,"description":"Per-occurrence limit for commercial general liability insurance"},{"id":"professional_liability_limit","type":"currency","label":"Professional Liability Limit","token":"{{professional_liability_limit}}","category":"insurance","required":false,"description":"Limit for errors and omissions insurance"},{"id":"cyber_liability_limit","type":"currency","label":"Cyber Liability Limit","token":"{{cyber_liability_limit}}","category":"insurance","required":false,"description":"Limit for cyber/privacy liability insurance"},{"id":"non_compete_term_months","type":"number","label":"Non-Compete Term (Months)","token":"{{non_compete_term_months}}","category":"restrictive_covenants","required":false,"description":"Duration of non-compete restriction after termination"},{"id":"non_compete_geography","type":"text","label":"Non-Compete Geography","token":"{{non_compete_geography}}","category":"restrictive_covenants","required":false,"description":"Geographic scope of restriction (must be reasonable under Texas law)"},{"id":"restricted_business_activities","type":"text","label":"Restricted Business Activities","token":"{{restricted_business_activities}}","category":"restrictive_covenants","required":false,"description":"Description of competitive activities covered by restriction"}]'::jsonb,
