',
  placeholders = '[{"id":"party_a_email","type":"email","label":"Your Email","token":"{{party_a_email}}","category":"party_a","required":true,"autofillKey":"email","description":"Email address for notices and communications"},{"id":"party_a_name","type":"text","label":"Your Name","token":"{{party_a_name}}","category":"party_a","required":true,"autofillKey":"name","description":"Printed name of authorized signatory"},{"id":"party_a_address","type":"textarea","label":"Your Address","token":"{{party_a_address}}","category":"party_a","required":false,"autofillKey":"address","description":"Mailing address for notice purposes"},{"id":"party_a_company","type":"text","label":"Your Company","token":"{{party_a_company}}","category":"party_a","required":false,"autofillKey":"company_name","description":"Legal entity name"},{"id":"party_a_title","type":"text","label":"Your Title","token":"{{party_a_title}}","category":"party_a","required":false,"autofillKey":"job_title","description":"Title of authorized signatory"},{"id":"party_b_email","type":"email","label":"Their Email","token":"{{party_b_email}}","category":"party_b","required":true,"description":"Email address for notices and communications"},{"id":"party_b_name","type":"text","label":"Their Name","token":"{{party_b_name}}","category":"party_b","required":true,"description":"Printed name of authorized signatory"},{"id":"party_b_address","type":"textarea","label":"Their Address","token":"{{party_b_address}}","category":"party_b","required":false,"description":"Mailing address for notice purposes"},{"id":"party_b_company","type":"text","label":"Their Company","token":"{{party_b_company}}","category":"party_b","required":false,"description":"Legal entity name"},{"id":"party_b_title","type":"text","label":"Their Title","token":"{{party_b_title}}","category":"party_b","required":false,"description":"Title of authorized signatory"},{"id":"effective_date","type":"date","label":"Effective Date","token":"{{effective_date}}","category":"dates","required":true,"description":"Date the agreement becomes effective"},{"id":"expiration_date","type":"date","label":"Expiration Date","token":"{{expiration_date}}","category":"dates","required":false,"description":"Date the agreement automatically expires, if any"},{"id":"signature_date","type":"date","label":"Signature Date","token":"{{signature_date}}","category":"dates","required":false,"description":"Date of execution"},{"id":"venue_county","type":"text","label":"Venue County","token":"{{venue_county}}","category":"terms","required":true,"description":"Texas county for exclusive venue and jurisdiction"},{"id":"confidentiality_period","type":"number","label":"Confidentiality Period (Years)","token":"{{confidentiality_period}}","category":"terms","required":false,"description":"Number of years confidentiality obligations apply (excluding Trade Secrets, which may continue as long as they remain trade secrets)"},{"id":"notice_period","type":"number","label":"Termination Notice Period (Days)","token":"{{notice_period}}","category":"terms","required":false,"description":"Days'' notice required to terminate the agreement"},{"id":"purpose","type":"textarea","label":"Purpose","token":"{{purpose}}","category":"terms","required":false,"description":"Business purpose for disclosures"},{"id":"return_destroy_days","type":"number","label":"Return/Destroy Period (Days)","token":"{{return_destroy_days}}","category":"terms","required":false,"description":"Number of days to return or destroy Confidential Information after request"},{"id":"security_incident_notice_hours","type":"number","label":"Security Incident Notice (Hours)","token":"{{security_incident_notice_hours}}","category":"terms","required":false,"description":"Target hours within which notice of a Security Incident should be provided where feasible"},{"id":"non_solicitation_period_months","type":"number","label":"Non-Solicitation Period (Months)","token":"{{non_solicitation_period_months}}","category":"optional_terms","required":false,"description":"Duration of optional non-solicitation obligations after termination/expiration"},{"id":"non_compete_period_months","type":"number","label":"Non-Compete/Non-Circumvention Period (Months)","token":"{{non_compete_period_months}}","category":"optional_terms","required":false,"description":"Duration of optional non-competition or non-circumvention obligations after termination/expiration"},{"id":"restricted_territory","type":"text","label":"Restricted Territory","token":"{{restricted_territory}}","category":"optional_terms","required":false,"description":"Geographic scope for optional restriction (e.g., State of Texas, United States, specific counties/metros)"},{"id":"restricted_activities","type":"textarea","label":"Restricted Activities","token":"{{restricted_activities}}","category":"optional_terms","required":false,"description":"Description of restricted competitive or circumvention activities for optional Section 12"}]'::jsonb,
