  placeholders = '[{"id":"party_a_email","type":"email","label":"Disclosing Party Email","token":"{{party_a_email}}","category":"party_a","required":true,"autofillKey":"email","description":"Email address for Disclosing Party notices"},{"id":"party_a_name","type":"text","label":"Disclosing Party Signer Name","token":"{{party_a_name}}","category":"party_a","required":true,"autofillKey":"name","description":"Full legal name of Disclosing Party signatory"},{"id":"party_a_address","type":"textarea","label":"Disclosing Party Address","token":"{{party_a_address}}","category":"party_a","required":false,"autofillKey":"address","description":"Mailing address"},{"id":"party_a_company","type":"text","label":"Disclosing Party Company","token":"{{party_a_company}}","category":"party_a","required":false,"autofillKey":"company_name","description":"Company or individual name of Disclosing Party"},{"id":"party_a_title","type":"text","label":"Disclosing Party Signer Title","token":"{{party_a_title}}","category":"party_a","required":false,"autofillKey":"job_title","description":"Title/role of Disclosing Party signatory"},{"id":"party_b_email","type":"email","label":"Receiving Party Email","token":"{{party_b_email}}","category":"party_b","required":true,"description":"Email address for Receiving Party notices"},{"id":"party_b_name","type":"text","label":"Receiving Party Signer Name","token":"{{party_b_name}}","category":"party_b","required":true,"description":"Full legal name of Receiving Party signatory"},{"id":"party_b_address","type":"textarea","label":"Receiving Party Address","token":"{{party_b_address}}","category":"party_b","required":false,"description":"Mailing address"},{"id":"party_b_company","type":"text","label":"Receiving Party Company","token":"{{party_b_company}}","category":"party_b","required":false,"description":"Company or individual name of Receiving Party"},{"id":"party_b_title","type":"text","label":"Receiving Party Signer Title","token":"{{party_b_title}}","category":"party_b","required":false,"description":"Title/role of Receiving Party signatory"},{"id":"effective_date","type":"date","label":"Effective Date","token":"{{effective_date}}","category":"dates","required":true,"description":"Date the agreement becomes effective"},{"id":"expiration_date","type":"date","label":"Expiration Date","token":"{{expiration_date}}","category":"dates","required":false,"description":"Date the agreement ends (if any)"},{"id":"signature_date","type":"date","label":"Signature Date","token":"{{signature_date}}","category":"dates","required":false,"description":"Date of signing"},{"id":"venue_county","type":"text","label":"Venue County","token":"{{venue_county}}","category":"terms","required":true,"description":"Specific Texas county for venue and jurisdiction"},{"id":"confidentiality_period","type":"number","label":"Confidentiality Period (Years)","token":"{{confidentiality_period}}","category":"terms","required":false,"description":"Number of years confidentiality obligations apply to non-trade secret information"},{"id":"notice_period","type":"number","label":"Termination Notice Period (Days)","token":"{{notice_period}}","category":"terms","required":false,"description":"Days'' notice required to terminate the agreement"},{"id":"purpose","type":"textarea","label":"Purpose","token":"{{purpose}}","category":"terms","required":false,"description":"Business purpose for disclosure"},{"id":"return_or_destroy_days","type":"number","label":"Return/Destroy Deadline (Days)","token":"{{return_or_destroy_days}}","category":"terms","required":false,"description":"Number of days to return or destroy confidential information after request or termination"},{"id":"security_incident_notice_hours","type":"number","label":"Security Incident Notice (Hours)","token":"{{security_incident_notice_hours}}","category":"terms","required":false,"description":"Hours within which Receiving Party must notify Disclosing Party of a security incident"},{"id":"include_indemnification","type":"text","label":"Include Indemnification (Yes/No)","token":"{{include_indemnification}}","category":"options","required":false,"description":"Set to ''Yes'' to include optional indemnification in Section 6.6"},{"id":"include_jury_waiver","type":"text","label":"Include Jury Trial Waiver (Yes/No)","token":"{{include_jury_waiver}}","category":"options","required":false,"description":"Set to ''Yes'' to include optional jury trial waiver in Section 7.5"},{"id":"include_audit_right","type":"text","label":"Include Audit/Assurance Right (Yes/No)","token":"{{include_audit_right}}","category":"options","required":false,"description":"Set to ''Yes'' to include optional compliance assurance in Section 8.16"},{"id":"restrictive_covenants_enabled","type":"text","label":"Enable Restrictive Covenants (Yes/No)","token":"{{restrictive_covenants_enabled}}","category":"options","required":false,"description":"Set to ''Yes'' to enable Section 9 (optional restrictive covenants)"},{"id":"non_solicit_period","type":"number","label":"Non-Solicitation Period (Months)","token":"{{non_solicit_period}}","category":"options","required":false,"description":"Months for non-solicitation restrictions in Section 9"},{"id":"non_compete_period","type":"number","label":"Non-Compete Period (Months)","token":"{{non_compete_period}}","category":"options","required":false,"description":"Months for optional non-compete in Section 9"},{"id":"non_compete_territory","type":"text","label":"Non-Compete Territory","token":"{{non_compete_territory}}","category":"options","required":false,"description":"Geographic territory for optional non-compete in Section 9"},{"id":"restricted_business_description","type":"textarea","label":"Restricted Business Description","token":"{{restricted_business_description}}","category":"options","required":false,"description":"Description of the Disclosing Party business to be protected in Section 9"}]'::jsonb,
  metadata = '{"word_count":5500,"clause_count":9,"generated_at":"2025-12-28T18:00:00.000Z","jurisdiction":"us_texas","generator_version":"gpt-5.2","placeholder_count":27,"gpt_enhanced":true,"gpt_model":"gpt-5.2","enhanced_at":"2025-12-29T00:56:53.947Z"}'::jsonb
